{
  "name": "FinanceMaster Pro",
  "description": "Um sistema completo de controle financeiro com dashboards, gestão de empréstimos, viagens, veículos e poupança, incluindo importação de Excel e lógica de compensação salarial."
}

export enum VehicleType {
  CAR = 'Carro',
  MOTORCYCLE = 'Moto'
}

export interface MonthlyExpense {
  inter: number;
  nubank: number;
  mPago: number;
  agua: number;
  energia: number;
  outros: number;
  pix: number;
}

export interface MonthlyIncome {
  salario: number;
  bonus: number;
  outros: number;
  recargaPay: number;
}

export interface MonthData {
  id: string;
  month: string;
  expenses: MonthlyExpense;
  income: MonthlyIncome;
}

export interface Loan {
  id: string;
  description: string;
  totalValue: number;
  installments: number;
  paidInstallments: number;
  installmentValue: number;
  interestMonthly: number;
}

export interface TripExpense {
  id: string;
  destination: string;
  carRental: number;
  fuel: number;
  food: number;
  others: number;
  creditCard: number;
  pix: number;
}

export interface VehicleExpense {
  id: string;
  type: VehicleType;
  description: string;
  value: number;
  date: string;
}

export interface SavingsTransaction {
  id: string;
  type: 'entrada' | 'retirada' | 'rendimento';
  value: number;
  date: string;
  description: string;
}

export interface AppState {
  months: MonthData[];
  loans: Loan[];
  trips: TripExpense[];
  vehicleExpenses: VehicleExpense[];
  savings: SavingsTransaction[];
}

export const formatCurrency = (value: number): string => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(value);
};

export const MONTHS_BR = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

export const calculateTotalExpenses = (exp: any): number => {
  return (exp.inter || 0) + (exp.nubank || 0) + (exp.mPago || 0) + 
         (exp.agua || 0) + (exp.energia || 0) + (exp.outros || 0) + (exp.pix || 0);
};

export const calculateTotalIncome = (inc: any): number => {
  return (inc.salario || 0) + (inc.bonus || 0) + (inc.outros || 0) + (inc.recargaPay || 0);
};

export const getNextMonthSalary = (currentMonthIdx: number, allMonths: any[]): number => {
  const nextIdx = (currentMonthIdx + 1) % 12;
  const nextMonthName = MONTHS_BR[nextIdx];
  const nextMonthData = allMonths.find(m => m.month === nextMonthName);
  return nextMonthData ? (nextMonthData.income.salario || 0) : 0;
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Table as TableIcon, 
  CreditCard, 
  Plane, 
  Car, 
  PiggyBank, 
  Plus, 
  Download, 
  Upload, 
  Sun, 
  Moon,
  ChevronRight,
  X,
  Trash2
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell
} from 'recharts';
import { 
  MonthData, 
  Loan, 
  TripExpense, 
  VehicleExpense, 
  SavingsTransaction, 
  AppState, 
  VehicleType 
} from './types';
import { 
  formatCurrency, 
  MONTHS_BR, 
  calculateTotalExpenses, 
  calculateTotalIncome,
  getNextMonthSalary
} from './utils';

// --- Sub-components (Local to file for simplicity in this single-file requirement context) ---

const Modal: React.FC<{ isOpen: boolean; onClose: () => void; title: string; children: React.ReactNode }> = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        <div className="flex items-center justify-between p-6 border-b dark:border-slate-700">
          <h2 className="text-xl font-bold dark:text-white">{title}</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-5 h-5 dark:text-slate-400" />
          </button>
        </div>
        <div className="p-6 overflow-y-auto custom-scrollbar">
          {children}
        </div>
      </div>
    </div>
  );
};

const TabButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button
    onClick={onClick}
    className={`flex items-center gap-2 px-4 py-3 rounded-lg font-medium transition-all duration-200 ${
      active 
        ? 'bg-primary-500 text-white shadow-lg shadow-primary-500/30' 
        : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
    }`}
  >
    {icon}
    <span className="hidden md:inline">{label}</span>
  </button>
);

const Card: React.FC<{ title: string; children: React.ReactNode; className?: string }> = ({ title, children, className = "" }) => (
  <div className={`bg-white dark:bg-slate-800 p-6 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm ${className}`}>
    <h3 className="text-sm font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4">{title}</h3>
    {children}
  </div>
);

// --- Main App Component ---

export default function App() {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'monthly' | 'loans' | 'travel' | 'vehicle' | 'savings'>('dashboard');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<MonthData | null>(null);

  // App State
  const [data, setData] = useState<AppState>({
    months: [],
    loans: [],
    trips: [],
    vehicleExpenses: [],
    savings: []
  });

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('finance_app_data');
    if (saved) {
      try {
        setData(JSON.parse(saved));
      } catch (e) {
        console.error("Error loading data", e);
      }
    }
  }, []);

  // Save to local storage on change
  useEffect(() => {
    localStorage.setItem('finance_app_data', JSON.stringify(data));
  }, [data]);

  // Handle Dark Mode
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  // Import Data (Simplificado para o formato do usuário via JSON ou prompt de importação manual)
  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const json = JSON.parse(evt.target?.result as string);
        setData(json);
        alert("Dados importados com sucesso!");
      } catch (err) {
        alert("Erro ao importar arquivo. Certifique-se que é um JSON válido exportado por este app.");
      }
    };
    reader.readAsText(file);
  };

  const handleExport = () => {
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `finance_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
  };

  const handleClearAll = () => {
    if (confirm("Tem certeza que deseja apagar TODOS os dados? Esta ação não pode ser desfeita.")) {
      setData({
        months: [],
        loans: [],
        trips: [],
        vehicleExpenses: [],
        savings: []
      });
    }
  };

  // --- Handlers for Adding Data ---

  const addMonth = () => {
    const monthName = prompt("Nome do Mês (ex: Janeiro):", MONTHS_BR[data.months.length % 12]);
    if (!monthName) return;

    const newMonth: MonthData = {
      id: Math.random().toString(36).substr(2, 9),
      month: monthName,
      expenses: { inter: 0, nubank: 0, mPago: 0, agua: 0, energia: 0, outros: 0, pix: 0 },
      income: { salario: 0, bonus: 0, outros: 0, recargaPay: 0 }
    };
    setData(prev => ({ ...prev, months: [...prev.months, newMonth] }));
  };

  const updateMonthField = (id: string, category: 'expenses' | 'income', field: string, value: string) => {
    const num = parseFloat(value) || 0;
    setData(prev => ({
      ...prev,
      months: prev.months.map(m => m.id === id ? {
        ...m,
        [category]: { ...m[category], [field]: num }
      } : m)
    }));
  };

  const addLoan = () => {
    const newLoan: Loan = {
      id: Math.random().toString(36).substr(2, 9),
      description: "Novo Empréstimo",
      totalValue: 0,
      installments: 12,
      paidInstallments: 0,
      installmentValue: 0,
      interestMonthly: 0
    };
    setData(prev => ({ ...prev, loans: [...prev.loans, newLoan] }));
  };

  const addTrip = () => {
    const newTrip: TripExpense = {
      id: Math.random().toString(36).substr(2, 9),
      destination: "Nova Viagem",
      carRental: 0,
      fuel: 0,
      food: 0,
      others: 0,
      creditCard: 0,
      pix: 0
    };
    setData(prev => ({ ...prev, trips: [...prev.trips, newTrip] }));
  };

  const addVehicleExpense = (type: VehicleType) => {
    const newExp: VehicleExpense = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      description: "Manutenção / Combustível",
      value: 0,
      date: new Date().toISOString().split('T')[0]
    };
    setData(prev => ({ ...prev, vehicleExpenses: [...prev.vehicleExpenses, newExp] }));
  };

  const addSavingsTransaction = (type: 'entrada' | 'retirada' | 'rendimento') => {
    const newTx: SavingsTransaction = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      value: 0,
      description: type.charAt(0).toUpperCase() + type.slice(1),
      date: new Date().toISOString().split('T')[0]
    };
    setData(prev => ({ ...prev, savings: [...prev.savings, newTx] }));
  };

  // --- Calculations for Charts ---

  const chartData = useMemo(() => {
    return data.months.map((m, idx) => {
      const expenses = calculateTotalExpenses(m.expenses);
      // Logic: Month X expenses paid with Month X+1 salary
      const relevantSalary = getNextMonthSalary(idx, data.months);
      const incomeTotal = calculateTotalIncome(m.income);

      return {
        name: m.month,
        gastos: expenses,
        ganhos: incomeTotal,
        balanco: relevantSalary - expenses
      };
    });
  }, [data.months]);

  const COLORS = ['#0ea5e9', '#f43f5e', '#10b981', '#f59e0b', '#8b5cf6'];

  return (
    <div className="min-h-screen transition-colors duration-200 dark:bg-slate-900 bg-slate-50 flex flex-col">
      {/* Sidebar / Navigation */}
      <header className="sticky top-0 z-40 w-full bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b dark:border-slate-800">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-primary-500 rounded-xl flex items-center justify-center shadow-lg shadow-primary-500/30">
              <PiggyBank className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold dark:text-white hidden sm:block">FinanceMaster</h1>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => setIsDarkMode(!isDarkMode)}
              className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400 transition-colors"
            >
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
            <div className="h-6 w-px bg-slate-200 dark:bg-slate-700 mx-2"></div>
            <label className="cursor-pointer p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400">
              <Upload className="w-5 h-5" />
              <input type="file" className="hidden" accept=".json" onChange={handleImport} />
            </label>
            <button 
              onClick={handleExport}
              className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400"
              title="Exportar Backup"
            >
              <Download className="w-5 h-5" />
            </button>
            <button 
              onClick={handleClearAll}
              className="p-2 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20 text-red-600 dark:text-red-400"
              title="Zerar Tudo"
            >
              <Trash2 className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto p-4 md:p-6 pb-24">
        {/* Tab Navigation */}
        <div className="flex items-center gap-2 overflow-x-auto pb-4 mb-6 custom-scrollbar">
          <TabButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard className="w-5 h-5" />} label="Painel" />
          <TabButton active={activeTab === 'monthly'} onClick={() => setActiveTab('monthly')} icon={<TableIcon className="w-5 h-5" />} label="Mensal" />
          <TabButton active={activeTab === 'loans'} onClick={() => setActiveTab('loans')} icon={<CreditCard className="w-5 h-5" />} label="Empréstimos" />
          <TabButton active={activeTab === 'travel'} onClick={() => setActiveTab('travel')} icon={<Plane className="w-5 h-5" />} label="Viagens" />
          <TabButton active={activeTab === 'vehicle'} onClick={() => setActiveTab('vehicle')} icon={<Car className="w-5 h-5" />} label="Veículos" />
          <TabButton active={activeTab === 'savings'} onClick={() => setActiveTab('savings')} icon={<PiggyBank className="w-5 h-5" />} label="Poupança" />
        </div>

        {/* Content Sections */}
        <div className="space-y-6">

          {/* DASHBOARD */}
          {activeTab === 'dashboard' && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <Card title="Visão Geral de Gastos vs Ganhos" className="md:col-span-2 lg:col-span-3 h-[400px]">
                {data.months.length === 0 ? (
                  <div className="h-full flex items-center justify-center text-slate-400 italic">Importe dados para ver o gráfico</div>
                ) : (
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chartData}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
                      <XAxis dataKey="name" stroke={isDarkMode ? '#94a3b8' : '#64748b'} />
                      <YAxis stroke={isDarkMode ? '#94a3b8' : '#64748b'} />
                      <Tooltip 
                        contentStyle={{ backgroundColor: isDarkMode ? '#1e293b' : '#ffffff', borderColor: isDarkMode ? '#334155' : '#e2e8f0' }}
                        itemStyle={{ color: isDarkMode ? '#f1f5f9' : '#0f172a' }}
                      />
                      <Legend />
                      <Bar dataKey="gastos" fill="#f43f5e" radius={[4, 4, 0, 0]} name="Gastos" />
                      <Bar dataKey="ganhos" fill="#10b981" radius={[4, 4, 0, 0]} name="Ganhos" />
                    </BarChart>
                  </ResponsiveContainer>
                )}
              </Card>

              <div className="grid grid-cols-1 gap-6 lg:col-span-3">
                 <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                    <Card title="Total em Gastos">
                       <p className="text-2xl font-bold text-red-500">
                         {formatCurrency(data.months.reduce((acc, m) => acc + calculateTotalExpenses(m.expenses), 0))}
                       </p>
                    </Card>
                    <Card title="Total em Ganhos">
                       <p className="text-2xl font-bold text-emerald-500">
                         {formatCurrency(data.months.reduce((acc, m) => acc + calculateTotalIncome(m.income), 0))}
                       </p>
                    </Card>
                    <Card title="Poupança Atual">
                       <p className="text-2xl font-bold text-primary-500">
                         {formatCurrency(data.savings.reduce((acc, s) => acc + (s.type === 'entrada' || s.type === 'rendimento' ? s.value : -s.value), 0))}
                       </p>
                    </Card>
                    <Card title="Dívida Empréstimos">
                       <p className="text-2xl font-bold text-amber-500">
                         {formatCurrency(data.loans.reduce((acc, l) => acc + (l.totalValue - (l.installmentValue * l.paidInstallments)), 0))}
                       </p>
                    </Card>
                 </div>
              </div>
            </div>
          )}

          {/* MONTHLY TABLE */}
          {activeTab === 'monthly' && (
            <Card title="Lançamentos Mensais">
              <div className="mb-4 flex justify-between items-center">
                <p className="text-sm text-slate-500 dark:text-slate-400">Clique em uma linha para ver detalhes e editar.</p>
                <button 
                  onClick={addMonth}
                  className="bg-primary-500 hover:bg-primary-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-md shadow-primary-500/20"
                >
                  <Plus className="w-4 h-4" /> Novo Mês
                </button>
              </div>
              <div className="overflow-x-auto border dark:border-slate-700 rounded-xl">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-700 text-slate-500 dark:text-slate-400 uppercase font-semibold">
                    <tr>
                      <th className="px-4 py-3">Mês</th>
                      <th className="px-4 py-3">Gastos</th>
                      <th className="px-4 py-3">Ganhos</th>
                      <th className="px-4 py-3">Balanço (Próx. Salário)</th>
                      <th className="px-4 py-3 text-right">Ação</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y dark:divide-slate-700">
                    {data.months.map((m, idx) => {
                      const totalExp = calculateTotalExpenses(m.expenses);
                      const totalInc = calculateTotalIncome(m.income);
                      const nextSal = getNextMonthSalary(idx, data.months);
                      const balance = nextSal - totalExp;

                      return (
                        <tr 
                          key={m.id} 
                          className="hover:bg-slate-50 dark:hover:bg-slate-700/50 cursor-pointer group transition-colors"
                          onClick={() => setSelectedMonth(m)}
                        >
                          <td className="px-4 py-4 font-medium dark:text-white">{m.month}</td>
                          <td className="px-4 py-4 text-red-500 font-medium">{formatCurrency(totalExp)}</td>
                          <td className="px-4 py-4 text-emerald-500 font-medium">{formatCurrency(totalInc)}</td>
                          <td className={`px-4 py-4 font-bold ${balance >= 0 ? 'text-emerald-500' : 'text-red-500'}`}>
                            {formatCurrency(balance)}
                          </td>
                          <td className="px-4 py-4 text-right">
                            <ChevronRight className="w-5 h-5 text-slate-300 group-hover:text-primary-500 ml-auto" />
                          </td>
                        </tr>
                      );
                    })}
                    {data.months.length === 0 && (
                      <tr>
                        <td colSpan={5} className="px-4 py-12 text-center text-slate-400 italic">Nenhum dado cadastrado. Use "Novo Mês" ou importe um backup.</td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </Card>
          )}

          {/* LOANS */}
          {activeTab === 'loans' && (
            <Card title="Controle de Empréstimos">
              <div className="mb-4">
                <button onClick={addLoan} className="bg-primary-500 hover:bg-primary-600 text-white px-4 py-2 rounded-lg flex items-center gap-2">
                  <Plus className="w-4 h-4" /> Novo Empréstimo
                </button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {data.loans.map(loan => (
                  <div key={loan.id} className="p-4 border dark:border-slate-700 rounded-xl space-y-3 relative group">
                    <button 
                      onClick={(e) => { e.stopPropagation(); setData(prev => ({ ...prev, loans: prev.loans.filter(l => l.id !== loan.id) })); }}
                      className="absolute top-2 right-2 p-1 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                    <input 
                      type="text" 
                      value={loan.description} 
                      onChange={(e) => setData(prev => ({ ...prev, loans: prev.loans.map(l => l.id === loan.id ? { ...l, description: e.target.value } : l) }))}
                      className="bg-transparent text-lg font-bold w-full dark:text-white border-b border-transparent focus:border-primary-500 outline-none"
                    />
                    <div className="grid grid-cols-2 gap-3 text-sm">
                      <div>
                        <label className="text-xs text-slate-400 uppercase">Valor Total</label>
                        <input 
                          type="number" value={loan.totalValue} 
                          onChange={(e) => setData(prev => ({ ...prev, loans: prev.loans.map(l => l.id === loan.id ? { ...l, totalValue: parseFloat(e.target.value) || 0 } : l) }))}
                          className="w-full p-2 rounded bg-slate-100 dark:bg-slate-700 dark:text-white"
                        />
                      </div>
                      <div>
                        <label className="text-xs text-slate-400 uppercase">Valor Parcela</label>
                        <input 
                          type="number" value={loan.installmentValue} 
                          onChange={(e) => setData(prev => ({ ...prev, loans: prev.loans.map(l => l.id === loan.id ? { ...l, installmentValue: parseFloat(e.target.value) || 0 } : l) }))}
                          className="w-full p-2 rounded bg-slate-100 dark:bg-slate-700 dark:text-white"
                        />
                      </div>
                      <div>
                        <label className="text-xs text-slate-400 uppercase">Parcelas Totais</label>
                        <input 
                          type="number" value={loan.installments} 
                          onChange={(e) => setData(prev => ({ ...prev, loans: prev.loans.map(l => l.id === loan.id ? { ...l, installments: parseInt(e.target.value) || 0 } : l) }))}
                          className="w-full p-2 rounded bg-slate-100 dark:bg-slate-700 dark:text-white"
                        />
                      </div>
                      <div>
                        <label className="text-xs text-slate-400 uppercase">Pagas</label>
                        <input 
                          type="number" value={loan.paidInstallments} 
                          onChange={(e) => setData(prev => ({ ...prev, loans: prev.loans.map(l => l.id === loan.id ? { ...l, paidInstallments: parseInt(e.target.value) || 0 } : l) }))}
                          className="w-full p-2 rounded bg-slate-100 dark:bg-slate-700 dark:text-white"
                        />
                      </div>
                    </div>
                    <div className="pt-2">
                      <div className="flex justify-between text-xs mb-1">
                        <span className="text-slate-400">Progresso</span>
                        <span className="dark:text-slate-300">{Math.round((loan.paidInstallments / loan.installments) * 100 || 0)}%</span>
                      </div>
