);

const Card: React.FC<{ title: string; children: React.ReactNode; className?: string }> = ({ title, children, className = "" }) => (
  <div className={`bg-white dark:bg-slate-800 p-6 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm ${className}`}>
    <h3 className="text-sm font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4">{title}</h3>
    {children}
  </div>
);

export default function App() {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'monthly' | 'loans' | 'travel' | 'vehicle' | 'savings'>('dashboard');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<MonthData | null>(null);

  const [data, setData] = useState<AppState>({
    months: [],
    loans: [],
    trips: [],
    vehicleExpenses: [],
    savings: []
  });

  useEffect(() => {
    const saved = localStorage.getItem('finance_app_data_v2');
    if (saved) {
      try {
        setData(JSON.parse(saved));
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('finance_app_data_v2', JSON.stringify(data));
  }, [data]);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const handleExcelImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const bstr = evt.target?.result;
      const wb = XLSX.read(bstr, { type: 'binary' });
      const wsname = wb.SheetNames[0];
      const ws = wb.Sheets[wsname];
      const json = XLSX.utils.sheet_to_json(ws);

      // Mapeamento simples: assume que as colunas batem com campos ou importa como novos meses
      // Aqui vamos apenas converter os dados básicos para a estrutura do app
      const importedMonths: MonthData[] = json.map((row: any, idx: number) => ({
        id: Math.random().toString(36).substr(2, 9),
        month: row.Mes || row.Mês || MONTHS_BR[idx % 12],
        year: row.Ano || new Date().getFullYear(),
        expenses: {
          inter: row.Inter || 0,
          nubank: row.Nubank || 0,
          mPago: row.MPago || 0,
          agua: row.Agua || 0,
          energia: row.Energia || 0,
          outros: row.Outros_Gastos || 0,
          pix: row.Pix || 0,
        },
        income: {
          salario: row.Salario || row.Salário || 0,
          bonus: row.Bonus || row.Bônus || 0,
          outros: row.Outros_Ganhos || 0,
          recargaPay: row.RecargaPay || 0,
        }
      }));

      setData(prev => ({ ...prev, months: [...prev.months, ...importedMonths] }));
      alert(`${importedMonths.length} registros importados com sucesso!`);
    };
    reader.readAsBinaryString(file);
  };

  const handleJSONImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        setData(JSON.parse(evt.target?.result as string));
        alert("Backup restaurado!");
      } catch (err) { alert("Erro no arquivo JSON."); }
    };
    reader.readAsText(file);
  };

  const addMonth = () => {
    const lastMonth = data.months[data.months.length - 1];
    let nextIndex = lastMonth ? (MONTHS_BR.indexOf(lastMonth.month) + 1) % 12 : 0;
    const monthName = MONTHS_BR[nextIndex];

    const newMonth: MonthData = {
      id: Math.random().toString(36).substr(2, 9),
      month: monthName,
      year: new Date().getFullYear(),
      expenses: { inter: 0, nubank: 0, mPago: 0, agua: 0, energia: 0, outros: 0, pix: 0 },
      income: { salario: 0, bonus: 0, outros: 0, recargaPay: 0 }
    };
    setData(prev => ({ ...prev, months: [...prev.months, newMonth] }));
  };

  const updateMonthField = (id: string, category: 'expenses' | 'income', field: string, value: string) => {
    const num = parseFloat(value) || 0;
    setData(prev => ({
      ...prev,
      months: prev.months.map(m => m.id === id ? {
        ...m,
        [category]: { ...m[category], [field]: num }
      } : m)
    }));
  };

  const addVehicleExpense = (type: VehicleType) => {
    const currentMonth = data.months[data.months.length - 1]?.month || MONTHS_BR[new Date().getMonth()];
    setData(prev => ({ 
      ...prev, 
      vehicleExpenses: [...prev.vehicleExpenses, {
        id: Math.random().toString(36).substr(2, 9),
        type,
        description: "Manutenção/Combustível",
        value: 0,
        month: currentMonth
      }] 
    }));
  };

  const addSavingsTransaction = (type: 'entrada' | 'retirada' | 'rendimento') => {
    const currentMonth = data.months[data.months.length - 1]?.month || MONTHS_BR[new Date().getMonth()];
    setData(prev => ({ 
      ...prev, 
      savings: [...prev.savings, {
        id: Math.random().toString(36).substr(2, 9),
        type,
        value: 0,
        description: type.charAt(0).toUpperCase() + type.slice(1),
        month: currentMonth
      }] 
    }));
  };

  const chartData = useMemo(() => {
    return data.months.map((m, idx) => {
      const expenses = calculateTotalExpenses(m.expenses);
      const relevantSalary = getNextMonthSalary(idx, data.months);
      const incomeTotal = calculateTotalIncome(m.income);
      return {
        name: m.month,
        gastos: expenses,
        ganhos: incomeTotal,
        balanco: relevantSalary - expenses
      };
    });
  }, [data.months]);

  return (
    <div className="min-h-screen transition-colors duration-200 dark:bg-slate-900 bg-slate-50 flex flex-col">
      <header className="sticky top-0 z-40 w-full bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b dark:border-slate-800">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-primary-500 rounded-xl flex items-center justify-center shadow-lg shadow-primary-500/30">
              <PiggyBank className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold dark:text-white hidden sm:block">FinanceMaster</h1>
          </div>

          <div className="flex items-center gap-2">
            <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400">
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
            <div className="h-6 w-px bg-slate-200 dark:bg-slate-700 mx-2"></div>
            <label className="cursor-pointer p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400" title="Importar Excel">
              <FileSpreadsheet className="w-5 h-5" />
              <input type="file" className="hidden" accept=".xlsx,.xls" onChange={handleExcelImport} />
            </label>
            <label className="cursor-pointer p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400" title="Restaurar Backup JSON">
              <Upload className="w-5 h-5" />
              <input type="file" className="hidden" accept=".json" onChange={handleJSONImport} />
            </label>
            <button onClick={() => {
              const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
              const url = URL.createObjectURL(blob);
              const a = document.createElement('a');
              a.href = url; a.download = 'finance_data.json'; a.click();
            }} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400" title="Exportar Backup">
              <Download className="w-5 h-5" />
            </button>
            <button onClick={() => confirm("Zerar todos os dados?") && setData({ months: [], loans: [], trips: [], vehicleExpenses: [], savings: [] })} className="p-2 rounded-lg hover:bg-red-50 text-red-600">
              <Trash2 className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto p-4 md:p-6 pb-24">
        <div className="flex items-center gap-2 overflow-x-auto pb-4 mb-6 custom-scrollbar">
          <TabButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard className="w-5 h-5" />} label="Painel" />
          <TabButton active={activeTab === 'monthly'} onClick={() => setActiveTab('monthly')} icon={<TableIcon className="w-5 h-5" />} label="Mensal" />
          <TabButton active={activeTab === 'loans'} onClick={() => setActiveTab('loans')} icon={<CreditCard className="w-5 h-5" />} label="Empréstimos" />
          <TabButton active={activeTab === 'travel'} onClick={() => setActiveTab('travel')} icon={<Plane className="w-5 h-5" />} label="Viagens" />
          <TabButton active={activeTab === 'vehicle'} onClick={() => setActiveTab('vehicle')} icon={<Car className="w-5 h-5" />} label="Veículos" />
          <TabButton active={activeTab === 'savings'} onClick={() => setActiveTab('savings')} icon={<PiggyBank className="w-5 h-5" />} label="Poupança" />
        </div>

        <div className="space-y-6">
          {activeTab === 'dashboard' && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <Card title="Evolução Financeira" className="md:col-span-3 h-[400px]">
                {data.months.length === 0 ? <div className="h-full flex items-center justify-center text-slate-400">Sem dados. Adicione um mês ou importe Excel.</div> : (
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chartData}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
                      <XAxis dataKey="name" stroke={isDarkMode ? '#94a3b8' : '#64748b'} />
                      <YAxis stroke={isDarkMode ? '#94a3b8' : '#64748b'} />
                      <Tooltip contentStyle={{ backgroundColor: isDarkMode ? '#1e293b' : '#fff', borderRadius: '8px' }} />
                      <Legend />
                      <Bar dataKey="gastos" fill="#f43f5e" name="Gastos" radius={[4,4,0,0]} />
                      <Bar dataKey="ganhos" fill="#10b981" name="Ganhos" radius={[4,4,0,0]} />
                    </BarChart>
                  </ResponsiveContainer>
                )}
              </Card>
            </div>
          )}

          {activeTab === 'monthly' && (
            <Card title="Tabela de Lançamentos">
              <div className="mb-4 flex justify-end">
                <button onClick={addMonth} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-primary-600 transition-all">
                  <Plus className="w-4 h-4" /> Novo Mês
                </button>
              </div>
              <div className="overflow-x-auto border dark:border-slate-700 rounded-xl">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-700 text-slate-500 uppercase font-semibold">
                    <tr><th className="px-4 py-3">Mês</th><th className="px-4 py-3">Gastos</th><th className="px-4 py-3">Ganhos</th><th className="px-4 py-3">Balanço (Próx. Sal)</th><th className="px-4 py-3 text-right">Ação</th></tr>
                  </thead>
                  <tbody className="divide-y dark:divide-slate-700">
                    {data.months.map((m, idx) => {
                      const totalExp = calculateTotalExpenses(m.expenses);
                      const totalInc = calculateTotalIncome(m.income);
                      const balance = getNextMonthSalary(idx, data.months) - totalExp;
                      return (
                        <tr key={m.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 cursor-pointer" onClick={() => setSelectedMonth(m)}>
                          <td className="px-4 py-4 font-medium dark:text-white">{m.month}</td>
                          <td className="px-4 py-4 text-red-500">{formatCurrency(totalExp)}</td>
                          <td className="px-4 py-4 text-emerald-500">{formatCurrency(totalInc)}</td>
                          <td className={`px-4 py-4 font-bold ${balance >= 0 ? 'text-emerald-500' : 'text-red-500'}`}>{formatCurrency(balance)}</td>
                          <td className="px-4 py-4 text-right"><ChevronRight className="w-5 h-5 text-slate-300 ml-auto" /></td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </Card>
          )}

          {activeTab === 'loans' && (
            <Card title="Empréstimos Ativos">
              <div className="mb-4"><button onClick={() => setData(prev => ({...prev, loans: [...prev.loans, { id: Math.random().toString(36).substr(2,9), description: "Novo", totalValue: 0, installments: 1, paidInstallments: 0, installmentValue: 0, interestMonthly: 0 }]}))} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2"><Plus className="w-4 h-4" /> Adicionar</button></div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {data.loans.map(loan => (
                  <div key={loan.id} className="p-4 border dark:border-slate-700 rounded-xl space-y-3 relative group">
                    <button onClick={() => setData(prev => ({...prev, loans: prev.loans.filter(l => l.id !== loan.id)}))} className="absolute top-2 right-2 text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 className="w-4 h-4"/></button>
                    <input type="text" value={loan.description} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, description: e.target.value} : l)}))} className="bg-transparent font-bold w-full dark:text-white outline-none border-b border-transparent focus:border-primary-500" />
                    <div className="grid grid-cols-2 gap-2 text-xs">
                      <div><label className="text-slate-400">Total</label><input type="number" value={loan.totalValue} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, totalValue: parseFloat(e.target.value) || 0} : l)}))} className="w-full p-2 bg-slate-100 dark:bg-slate-700 rounded dark:text-white" /></div>
                      <div><label className="text-slate-400">Valor Parcela</label><input type="number" value={loan.installmentValue} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, installmentValue: parseFloat(e.target.value) || 0} : l)}))} className="w-full p-2 bg-slate-100 dark:bg-slate-700 rounded dark:text-white" /></div>
                      <div><label className="text-slate-400">Parcelas</label><input type="number" value={loan.installments} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, installments: parseInt(e.target.value) || 1} : l)}))} className="w-full p-2 bg-slate-100 dark:bg-slate-700 rounded dark:text-white" /></div>
                      <div><label className="text-slate-400">Pagas</label><input type="number" value={loan.paidInstallments} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, paidInstallments: parseInt(e.target.value) || 0} : l)}))} className="w-full p-2 bg-slate-100 dark:bg-slate-700 rounded dark:text-white" /></div>
                    </div>
                  </div>
                ))}
              </div>
            </Card>
          )}

          {activeTab === 'vehicle' && (
            <Card title="Controle de Veículos">
              <div className="flex gap-2 mb-4">
                <button onClick={() => addVehicleExpense(VehicleType.CAR)} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2"><Plus className="w-4 h-4" /> Gasto Carro</button>
                <button onClick={() => addVehicleExpense(VehicleType.MOTORCYCLE)} className="bg-amber-500 text-white px-4 py-2 rounded-lg flex items-center gap-2"><Plus className="w-4 h-4" /> Gasto Moto</button>
              </div>
              <div className="overflow-x-auto border dark:border-slate-700 rounded-xl">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-700 text-slate-500 uppercase">
                    <tr><th className="px-4 py-3">Tipo</th><th className="px-4 py-3">Descrição</th><th className="px-4 py-3">Mês</th><th className="px-4 py-3">Valor</th><th className="px-4 py-3">Ação</th></tr>
                  </thead>
                  <tbody className="divide-y dark:divide-slate-700">
                    {data.vehicleExpenses.map(exp => (
                      <tr key={exp.id} className="dark:text-white">
                        <td className="px-4 py-3 text-xs font-bold">{exp.type}</td>
                        <td className="px-4 py-3"><input type="text" value={exp.description} onChange={(e) => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.map(v => v.id === exp.id ? {...v, description: e.target.value} : v)}))} className="bg-transparent w-full outline-none" /></td>
                        <td className="px-4 py-3">
                          <select value={exp.month} onChange={(e) => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.map(v => v.id === exp.id ? {...v, month: e.target.value} : v)}))} className="bg-transparent dark:bg-slate-800 outline-none">
                            {MONTHS_BR.map(m => <option key={m} value={m}>{m}</option>)}
                          </select>
                        </td>
                        <td className="px-4 py-3"><input type="number" value={exp.value} onChange={(e) => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.map(v => v.id === exp.id ? {...v, value: parseFloat(e.target.value) || 0} : v)}))} className="bg-transparent w-24 outline-none font-bold" /></td>
                        <td className="px-4 py-3"><button onClick={() => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.filter(v => v.id !== exp.id)}))} className="text-red-500"><Trash2 className="w-4 h-4" /></button></td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </Card>
          )}

          {activeTab === 'savings' && (
            <Card title="Minha Poupança">
              <div className="flex gap-2 mb-4">
                <button onClick={() => addSavingsTransaction('entrada')} className="bg-emerald-500 text-white px-4 py-2 rounded-lg flex items-center gap-2"><Plus className="w-4 h-4" /> Entrada</button>
                <button onClick={() => addSavingsTransaction('retirada')} className="bg-red-500 text-white px-4 py-2 rounded-lg flex items-center gap-2"><Plus className="w-4 h-4" /> Retirada</button>
              </div>
              <div className="overflow-x-auto border dark:border-slate-700 rounded-xl">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-700 text-slate-500 uppercase">
                    <tr><th className="px-4 py-3">Tipo</th><th className="px-4 py-3">Descrição</th><th className="px-4 py-3">Mês</th><th className="px-4 py-3">Valor</th><th className="px-4 py-3">Ação</th></tr>
                  </thead>
                  <tbody className="divide-y dark:divide-slate-700">
                    {data.savings.map(s => (
                      <tr key={s.id} className="dark:text-white">
                        <td className={`px-4 py-3 text-xs font-bold uppercase ${s.type === 'entrada' ? 'text-emerald-500' : 'text-red-500'}`}>{s.type}</td>
                        <td className="px-4 py-3"><input type="text" value={s.description} onChange={(e) => setData(prev => ({...prev, savings: prev.savings.map(item => item.id === s.id ? {...item, description: e.target.value} : item)}))} className="bg-transparent w-full outline-none" /></td>
                        <td className="px-4 py-3">
                          <select value={s.month} onChange={(e) => setData(prev => ({...prev, savings: prev.savings.map(item => item.id === s.id ? {...item, month: e.target.value} : item)}))} className="bg-transparent dark:bg-slate-800 outline-none">
                            {MONTHS_BR.map(m => <option key={m} value={m}>{m}</option>)}
                          </select>
                        </td>
                        <td className="px-4 py-3"><input type="number" value={s.value} onChange={(e) => setData(prev => ({...prev, savings: prev.savings.map(item => item.id === s.id ? {...item, value: parseFloat(e.target.value) || 0} : item)}))} className="bg-transparent w-24 outline-none font-bold" /></td>
                        <td className="px-4 py-3"><button onClick={() => setData(prev => ({...prev, savings: prev.savings.filter(item => item.id !== s.id)}))} className="text-red-500"><Trash2 className="w-4 h-4" /></button></td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </Card>
          )}

          {activeTab === 'travel' && (
            <Card title="Viagens">
              <div className="mb-4"><button onClick={() => setData(prev => ({...prev, trips: [...prev.trips, { id: Math.random().toString(36).substr(2,9), destination: "Nova Viagem", carRental: 0, fuel: 0, food: 0, others: 0, creditCard: 0, pix: 0 }] }))} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2"><Plus className="w-4 h-4" /> Nova Viagem</button></div>
              <div className="space-y-4">
                {data.trips.map(trip => (
                  <div key={trip.id} className="p-4 border dark:border-slate-700 rounded-xl space-y-4">
                    <div className="flex justify-between items-center"><input type="text" value={trip.destination} onChange={(e) => setData(prev => ({...prev, trips: prev.trips.map(t => t.id === trip.id ? {...t, destination: e.target.value} : t)}))} className="bg-transparent font-bold dark:text-white outline-none border-b border-transparent focus:border-primary-500 text-lg" /><button onClick={() => setData(prev => ({...prev, trips: prev.trips.filter(t => t.id !== trip.id)}))} className="text-red-500"><Trash2 className="w-5 h-5"/></button></div>
                    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-3 text-xs">
                      {['carRental', 'fuel', 'food', 'others', 'creditCard', 'pix'].map(f => (
                        <div key={f}><label className="text-slate-400 capitalize">{f}</label><input type="number" value={(trip as any)[f]} onChange={(e) => setData(prev => ({...prev, trips: prev.trips.map(t => t.id === trip.id ? {...t, [f]: parseFloat(e.target.value) || 0} : t)}))} className="w-full p-2 bg-slate-100 dark:bg-slate-700 rounded dark:text-white" /></div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </Card>
          )}
        </div>
      </main>

      <Modal isOpen={!!selectedMonth} onClose={() => setSelectedMonth(null)} title={`Lançamentos: ${selectedMonth?.month}`}>
        {selectedMonth && (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                <h4 className="font-bold text-red-500 border-b pb-1">Gastos</h4>
                <div className="grid grid-cols-2 gap-3">
                  {Object.keys(selectedMonth.expenses).map(key => (
                    <div key={key}><label className="text-[10px] text-slate-400 uppercase">{key}</label><input type="number" value={(selectedMonth.expenses as any)[key]} onChange={(e) => updateMonthField(selectedMonth.id, 'expenses', key, e.target.value)} className="w-full p-2 bg-slate-50 dark:bg-slate-700 rounded-lg dark:text-white outline-none focus:ring-1 focus:ring-primary-500" /></div>
                  ))}
                </div>
              </div>
              <div className="space-y-4">
                <h4 className="font-bold text-emerald-500 border-b pb-1">Ganhos</h4>
                <div className="grid grid-cols-2 gap-3">
                  {Object.keys(selectedMonth.income).map(key => (
                    <div key={key}><label className="text-[10px] text-slate-400 uppercase">{key}</label><input type="number" value={(selectedMonth.income as any)[key]} onChange={(e) => updateMonthField(selectedMonth.id, 'income', key, e.target.value)} className="w-full p-2 bg-slate-50 dark:bg-slate-700 rounded-lg dark:text-white outline-none focus:ring-1 focus:ring-primary-500" /></div>
                  ))}
                </div>
              </div>
            </div>
            <div className="p-4 bg-slate-100 dark:bg-slate-900 rounded-xl flex justify-between items-center">
              <div><p className="text-xs text-slate-500">Saldo Mensal</p><p className={`text-xl font-bold ${calculateTotalIncome(selectedMonth.income) - calculateTotalExpenses(selectedMonth.expenses) >= 0 ? 'text-emerald-500' : 'text-red-500'}`}>{formatCurrency(calculateTotalIncome(selectedMonth.income) - calculateTotalExpenses(selectedMonth.expenses))}</p></div>
              <button onClick={() => { setData(prev => ({...prev, months: prev.months.filter(m => m.id !== selectedMonth.id)})); setSelectedMonth(null); }} className="text-red-500 hover:underline flex items-center gap-1"><Trash2 className="w-4 h-4" /> Excluir</button>
            </div>
          </div>
        )}
      </Modal>

      <footer className="md:hidden fixed bottom-0 w-full bg-white dark:bg-slate-900 border-t dark:border-slate-800 p-2 grid grid-cols-6 gap-1 z-40">
        <button onClick={() => setActiveTab('dashboard')} className={`p-2 flex flex-col items-center ${activeTab === 'dashboard' ? 'text-primary-500' : 'text-slate-400'}`}><LayoutDashboard className="w-5 h-5" /><span className="text-[9px]">Painel</span></button>
        <button onClick={() => setActiveTab('monthly')} className={`p-2 flex flex-col items-center ${activeTab === 'monthly' ? 'text-primary-500' : 'text-slate-400'}`}><TableIcon className="w-5 h-5" /><span className="text-[9px]">Meses</span></button>
        <button onClick={() => setActiveTab('loans')} className={`p-2 flex flex-col items-center ${activeTab === 'loans' ? 'text-primary-500' : 'text-slate-400'}`}><CreditCard className="w-5 h-5" /><span className="text-[9px]">Emp.</span></button>
        <button onClick={() => setActiveTab('travel')} className={`p-2 flex flex-col items-center ${activeTab === 'travel' ? 'text-primary-500' : 'text-slate-400'}`}><Plane className="w-5 h-5" /><span className="text-[9px]">Viagem</span></button>
        <button onClick={() => setActiveTab('vehicle')} className={`p-2 flex flex-col items-center ${activeTab === 'vehicle' ? 'text-primary-500' : 'text-slate-400'}`}><Car className="w-5 h-5" /><span className="text-[9px]">Auto</span></button>
        <button onClick={() => setActiveTab('savings')} className={`p-2 flex flex-col items-center ${activeTab === 'savings' ? 'text-primary-500' : 'text-slate-400'}`}><PiggyBank className="w-5 h-5" /><span className="text-[9px]">Poupa</span></button>
      </footer>
    </div>
  );
}

export enum VehicleType {
  CAR = 'Carro',
  MOTORCYCLE = 'Moto'
}

export enum VehicleCategory {
  MAINTENANCE = 'Manutenção',
  FUEL = 'Combustível'
}

export interface MonthlyExpense {
  inter: number;
  nubank: number;
  mPago: number;
  agua: number;
  energia: number;
  outros: number;
  pix: number;
}

export interface MonthlyIncome {
  salario: number;
  bonus: number;
  outros: number;
  recargaPay: number;
}

export interface MonthData {
  id: string;
  month: string;
  year: number;
  expenses: MonthlyExpense;
  income: MonthlyIncome;
}

export interface Loan {
  id: string;
  description: string;
  totalValue: number;
  installments: number;
  paidInstallments: number;
  installmentValue: number;
  interestMonthly: number;
}

export interface TripExpense {
  id: string;
  destination: string;
  month: string;
  carRental: number;
  fuel: number;
  food: number;
  others: number;
  creditCard: number;
  pix: number;
}

export interface VehicleExpense {
  id: string;
  type: VehicleType;
  category: VehicleCategory;
  description: string;
  value: number;
  month: string;
}

export interface SavingsTransaction {
  id: string;
  type: 'entrada' | 'retirada' | 'rendimento';
  value: number;
  month: string;
  description: string;
}

export interface AppState {
  months: MonthData[];
  loans: Loan[];
  trips: TripExpense[];
  vehicleExpenses: VehicleExpense[];
  savings: SavingsTransaction[];
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Table as TableIcon, 
  CreditCard, 
  Plane, 
  Car, 
  PiggyBank, 
  Plus, 
  Download, 
  Upload, 
  Sun, 
  Moon,
  ChevronRight,
  X,
  Trash2,
  FileSpreadsheet,
  Settings
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer
} from 'recharts';
import { 
  MonthData, 
  Loan, 
  TripExpense, 
  VehicleExpense, 
  SavingsTransaction, 
  AppState, 
  VehicleType,
  VehicleCategory
} from './types';
import { 
  formatCurrency, 
  MONTHS_BR, 
  calculateTotalExpenses, 
  calculateTotalIncome,
  getNextMonthSalary
} from './utils';

// Declare XLSX from global script
declare const XLSX: any;

const Modal: React.FC<{ isOpen: boolean; onClose: () => void; title: string; children: React.ReactNode }> = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        <div className="flex items-center justify-between p-6 border-b dark:border-slate-700">
          <h2 className="text-xl font-bold dark:text-white">{title}</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-5 h-5 dark:text-slate-400" />
          </button>
        </div>
        <div className="p-6 overflow-y-auto custom-scrollbar">
          {children}
        </div>
      </div>
    </div>
  );
};

const TabButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button
    onClick={onClick}
    className={`flex items-center gap-2 px-4 py-3 rounded-lg font-medium transition-all duration-200 ${
      active 
        ? 'bg-primary-500 text-white shadow-lg shadow-primary-500/30' 
        : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
    }`}
  >
    {icon}
    <span className="hidden md:inline">{label}</span>
  </button>
);

const Card: React.FC<{ title: string; children: React.ReactNode; className?: string }> = ({ title, children, className = "" }) => (
  <div className={`bg-white dark:bg-slate-800 p-6 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm ${className}`}>
    <h3 className="text-sm font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4">{title}</h3>
    {children}
  </div>
);

export default function App() {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'monthly' | 'loans' | 'travel' | 'vehicle' | 'savings'>('dashboard');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [selectedMonth, setSelectedMonth] = useState<MonthData | null>(null);

  const [data, setData] = useState<AppState>({
    months: [],
    loans: [],
    trips: [],
    vehicleExpenses: [],
    savings: []
  });

  useEffect(() => {
    const saved = localStorage.getItem('finance_app_data_v3');
    if (saved) {
      try {
        setData(JSON.parse(saved));
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('finance_app_data_v3', JSON.stringify(data));
  }, [data]);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const handleExcelImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      const bstr = evt.target?.result;
      const wb = XLSX.read(bstr, { type: 'binary' });
      const wsname = wb.SheetNames[0];
      const ws = wb.Sheets[wsname];
      const json = XLSX.utils.sheet_to_json(ws);

      const importedMonths: MonthData[] = json.map((row: any, idx: number) => ({
        id: Math.random().toString(36).substr(2, 9),
        month: row.Mes || row.Mês || MONTHS_BR[idx % 12],
        year: row.Ano || new Date().getFullYear(),
        expenses: {
          inter: row.Inter || 0,
          nubank: row.Nubank || 0,
          mPago: row.MPago || 0,
          agua: row.Agua || 0,
          energia: row.Energia || 0,
          outros: row.Outros_Gastos || 0,
          pix: row.Pix || 0,
        },
        income: {
          salario: row.Salario || row.Salário || 0,
          bonus: row.Bonus || row.Bônus || 0,
          outros: row.Outros_Ganhos || 0,
          recargaPay: row.RecargaPay || 0,
        }
      }));

      setData(prev => ({ ...prev, months: [...prev.months, ...importedMonths] }));
      alert(`${importedMonths.length} registros importados com sucesso!`);
    };
    reader.readAsBinaryString(file);
  };

  const handleJSONImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        setData(JSON.parse(evt.target?.result as string));
        alert("Backup restaurado!");
      } catch (err) { alert("Erro no arquivo JSON."); }
    };
    reader.readAsText(file);
  };

  const addMonth = () => {
    const lastMonth = data.months[data.months.length - 1];
    let nextIndex = lastMonth ? (MONTHS_BR.indexOf(lastMonth.month) + 1) % 12 : 0;
    const monthName = MONTHS_BR[nextIndex];

    const newMonth: MonthData = {
      id: Math.random().toString(36).substr(2, 9),
      month: monthName,
      year: new Date().getFullYear(),
      expenses: { inter: 0, nubank: 0, mPago: 0, agua: 0, energia: 0, outros: 0, pix: 0 },
      income: { salario: 0, bonus: 0, outros: 0, recargaPay: 0 }
    };
    setData(prev => ({ ...prev, months: [...prev.months, newMonth] }));
    // Open modal to let user change the month if they want
    setSelectedMonth(newMonth);
  };

  const updateMonthField = (id: string, category: 'expenses' | 'income', field: string, value: string) => {
    const num = parseFloat(value) || 0;
    setData(prev => ({
      ...prev,
      months: prev.months.map(m => m.id === id ? {
        ...m,
        [category]: { ...m[category], [field]: num }
      } : m)
    }));
  };

  const addVehicleExpense = (type: VehicleType) => {
    const currentMonth = data.months[data.months.length - 1]?.month || MONTHS_BR[new Date().getMonth()];
    setData(prev => ({ 
      ...prev, 
      vehicleExpenses: [...prev.vehicleExpenses, {
        id: Math.random().toString(36).substr(2, 9),
        type,
        category: VehicleCategory.FUEL,
        description: "Abastecimento",
        value: 0,
        month: currentMonth
      }] 
    }));
  };

  const addSavingsTransaction = (type: 'entrada' | 'retirada' | 'rendimento') => {
    const currentMonth = data.months[data.months.length - 1]?.month || MONTHS_BR[new Date().getMonth()];
    setData(prev => ({ 
      ...prev, 
      savings: [...prev.savings, {
        id: Math.random().toString(36).substr(2, 9),
        type,
        value: 0,
        description: type.charAt(0).toUpperCase() + type.slice(1),
        month: currentMonth
      }] 
    }));
  };

  const chartData = useMemo(() => {
    return data.months.map((m, idx) => {
      const expenses = calculateTotalExpenses(m.expenses);
      const relevantSalary = getNextMonthSalary(idx, data.months);
      const incomeTotal = calculateTotalIncome(m.income);
      return {
        name: m.month,
        gastos: expenses,
        ganhos: incomeTotal,
        balanco: relevantSalary - expenses
      };
    });
  }, [data.months]);

  return (
    <div className="min-h-screen transition-colors duration-200 dark:bg-slate-900 bg-slate-50 flex flex-col">
      <header className="sticky top-0 z-40 w-full bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b dark:border-slate-800">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-primary-500 rounded-xl flex items-center justify-center shadow-lg shadow-primary-500/30">
              <PiggyBank className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold dark:text-white hidden sm:block">FinanceMaster</h1>
          </div>

          <div className="flex items-center gap-2">
            <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400">
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
            <div className="h-6 w-px bg-slate-200 dark:bg-slate-700 mx-2"></div>
            <label className="cursor-pointer p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400" title="Importar Excel">
              <FileSpreadsheet className="w-5 h-5" />
              <input type="file" className="hidden" accept=".xlsx,.xls" onChange={handleExcelImport} />
            </label>
            <label className="cursor-pointer p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400" title="Restaurar Backup JSON">
              <Upload className="w-5 h-5" />
              <input type="file" className="hidden" accept=".json" onChange={handleJSONImport} />
            </label>
            <button onClick={() => {
              const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
              const url = URL.createObjectURL(blob);
              const a = document.createElement('a');
              a.href = url; a.download = 'finance_data.json'; a.click();
            }} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400" title="Exportar Backup">
              <Download className="w-5 h-5" />
            </button>
            <button onClick={() => confirm("Zerar todos os dados?") && setData({ months: [], loans: [], trips: [], vehicleExpenses: [], savings: [] })} className="p-2 rounded-lg hover:bg-red-50 text-red-600">
              <Trash2 className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto p-4 md:p-6 pb-24">
        <div className="flex items-center gap-2 overflow-x-auto pb-4 mb-6 custom-scrollbar border-b dark:border-slate-800">
          <TabButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard className="w-5 h-5" />} label="Painel" />
          <TabButton active={activeTab === 'monthly'} onClick={() => setActiveTab('monthly')} icon={<TableIcon className="w-5 h-5" />} label="Mensal" />
          <TabButton active={activeTab === 'loans'} onClick={() => setActiveTab('loans')} icon={<CreditCard className="w-5 h-5" />} label="Empréstimos" />
          <TabButton active={activeTab === 'travel'} onClick={() => setActiveTab('travel')} icon={<Plane className="w-5 h-5" />} label="Viagens" />
          <TabButton active={activeTab === 'vehicle'} onClick={() => setActiveTab('vehicle')} icon={<Car className="w-5 h-5" />} label="Veículos" />
          <TabButton active={activeTab === 'savings'} onClick={() => setActiveTab('savings')} icon={<PiggyBank className="w-5 h-5" />} label="Poupança" />
        </div>

        <div className="space-y-6">
          {activeTab === 'dashboard' && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <Card title="Evolução Financeira" className="md:col-span-3 h-[400px]">
                {data.months.length === 0 ? <div className="h-full flex items-center justify-center text-slate-400">Sem dados. Adicione um mês ou importe Excel.</div> : (
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chartData}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
                      <XAxis dataKey="name" stroke={isDarkMode ? '#94a3b8' : '#64748b'} />
                      <YAxis stroke={isDarkMode ? '#94a3b8' : '#64748b'} />
                      <Tooltip contentStyle={{ backgroundColor: isDarkMode ? '#1e293b' : '#fff', borderRadius: '8px' }} />
                      <Legend />
                      <Bar dataKey="gastos" fill="#f43f5e" name="Gastos" radius={[4,4,0,0]} />
                      <Bar dataKey="ganhos" fill="#10b981" name="Ganhos" radius={[4,4,0,0]} />
                    </BarChart>
                  </ResponsiveContainer>
                )}
              </Card>
            </div>
          )}

          {activeTab === 'monthly' && (
            <Card title="Tabela de Lançamentos">
              <div className="mb-4 flex justify-end">
                <button onClick={addMonth} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-primary-600 transition-all">
                  <Plus className="w-4 h-4" /> Novo Mês
                </button>
              </div>
              <div className="overflow-x-auto border dark:border-slate-700 rounded-xl">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-700 text-slate-500 uppercase font-semibold">
                    <tr><th className="px-4 py-3">Mês</th><th className="px-4 py-3">Gastos</th><th className="px-4 py-3">Ganhos</th><th className="px-4 py-3">Balanço (Próx. Sal)</th><th className="px-4 py-3 text-right">Ação</th></tr>
                  </thead>
                  <tbody className="divide-y dark:divide-slate-700">
                    {data.months.map((m, idx) => {
                      const totalExp = calculateTotalExpenses(m.expenses);
                      const totalInc = calculateTotalIncome(m.income);
                      const balance = getNextMonthSalary(idx, data.months) - totalExp;
                      return (
                        <tr key={m.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 cursor-pointer" onClick={() => setSelectedMonth(m)}>
                          <td className="px-4 py-4 font-medium dark:text-white">{m.month}</td>
                          <td className="px-4 py-4 text-red-500">{formatCurrency(totalExp)}</td>
                          <td className="px-4 py-4 text-emerald-500">{formatCurrency(totalInc)}</td>
                          <td className={`px-4 py-4 font-bold ${balance >= 0 ? 'text-emerald-500' : 'text-red-500'}`}>{formatCurrency(balance)}</td>
                          <td className="px-4 py-4 text-right"><ChevronRight className="w-5 h-5 text-slate-300 ml-auto" /></td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </Card>
          )}

          {activeTab === 'loans' && (
            <Card title="Empréstimos Ativos">
              <div className="mb-4"><button onClick={() => setData(prev => ({...prev, loans: [...prev.loans, { id: Math.random().toString(36).substr(2,9), description: "Novo", totalValue: 0, installments: 1, paidInstallments: 0, installmentValue: 0, interestMonthly: 0 }]}))} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2"><Plus className="w-4 h-4" /> Adicionar</button></div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {data.loans.map(loan => (
                  <div key={loan.id} className="p-4 border dark:border-slate-700 rounded-xl space-y-3 relative group">
                    <button onClick={() => setData(prev => ({...prev, loans: prev.loans.filter(l => l.id !== loan.id)}))} className="absolute top-2 right-2 text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 className="w-4 h-4"/></button>
                    <input type="text" value={loan.description} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, description: e.target.value} : l)}))} className="bg-transparent font-bold w-full dark:text-white outline-none border-b border-transparent focus:border-primary-500" />
                    <div className="grid grid-cols-2 gap-2 text-xs">
                      <div><label className="text-slate-400">Total</label><input type="number" value={loan.totalValue} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, totalValue: parseFloat(e.target.value) || 0} : l)}))} className="w-full p-2 bg-slate-100 dark:bg-slate-700 rounded dark:text-white" /></div>
                      <div><label className="text-slate-400">Valor Parcela</label><input type="number" value={loan.installmentValue} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, installmentValue: parseFloat(e.target.value) || 0} : l)}))} className="w-full p-2 bg-slate-100 dark:bg-slate-700 rounded dark:text-white" /></div>
                      <div><label className="text-slate-400">Parcelas</label><input type="number" value={loan.installments} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, installments: parseInt(e.target.value) || 1} : l)}))} className="w-full p-2 bg-slate-100 dark:bg-slate-700 rounded dark:text-white" /></div>
                      <div><label className="text-slate-400">Pagas</label><input type="number" value={loan.paidInstallments} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, paidInstallments: parseInt(e.target.value) || 0} : l)}))} className="w-full p-2 bg-slate-100 dark:bg-slate-700 rounded dark:text-white" /></div>
                    </div>
                  </div>
                ))}
              </div>
            </Card>
          )}

          {activeTab === 'vehicle' && (
            <Card title="Controle de Veículos">
              <div className="flex gap-2 mb-4">
                <button onClick={() => addVehicleExpense(VehicleType.CAR)} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-all hover:scale-105 active:scale-95"><Plus className="w-4 h-4" /> Gasto Carro</button>
                <button onClick={() => addVehicleExpense(VehicleType.MOTORCYCLE)} className="bg-amber-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-all hover:scale-105 active:scale-95"><Plus className="w-4 h-4" /> Gasto Moto</button>
              </div>
              <div className="overflow-x-auto border dark:border-slate-700 rounded-xl shadow-sm">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-700 text-slate-500 uppercase">
                    <tr>
                      <th className="px-4 py-3">Tipo</th>
                      <th className="px-4 py-3">Categoria</th>
                      <th className="px-4 py-3">Descrição</th>
                      <th className="px-4 py-3">Mês</th>
                      <th className="px-4 py-3">Valor</th>
                      <th className="px-4 py-3">Ação</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y dark:divide-slate-700">
                    {data.vehicleExpenses.map(exp => (
                      <tr key={exp.id} className="dark:text-white transition-colors hover:bg-slate-50 dark:hover:bg-slate-800/30">
                        <td className="px-4 py-3 text-xs font-bold">{exp.type}</td>
                        <td className="px-4 py-3">
                          <select 
                            value={exp.category || VehicleCategory.FUEL} 
                            onChange={(e) => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.map(v => v.id === exp.id ? {...v, category: e.target.value as VehicleCategory} : v)}))} 
                            className="bg-slate-100 dark:bg-slate-700 rounded px-2 py-1 outline-none text-xs"
                          >
                            {Object.values(VehicleCategory).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                          </select>
                        </td>
                        <td className="px-4 py-3"><input type="text" value={exp.description} onChange={(e) => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.map(v => v.id === exp.id ? {...v, description: e.target.value} : v)}))} className="bg-transparent w-full outline-none focus:border-b border-primary-500" /></td>
                        <td className="px-4 py-3">
                          <select value={exp.month} onChange={(e) => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.map(v => v.id === exp.id ? {...v, month: e.target.value} : v)}))} className="bg-transparent dark:bg-slate-800 outline-none">
                            {MONTHS_BR.map(m => <option key={m} value={m}>{m}</option>)}
                          </select>
                        </td>
                        <td className="px-4 py-3"><input type="number" value={exp.value} onChange={(e) => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.map(v => v.id === exp.id ? {...v, value: parseFloat(e.target.value) || 0} : v)}))} className="bg-transparent w-24 outline-none font-bold" /></td>
                        <td className="px-4 py-3"><button onClick={() => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.filter(v => v.id !== exp.id)}))} className="text-red-500 hover:scale-110"><Trash2 className="w-4 h-4" /></button></td>
                      </tr>
                    ))}
                    {data.vehicleExpenses.length === 0 && (
                      <tr><td colSpan={6} className="px-4 py-8 text-center text-slate-400 italic">Nenhum gasto com veículo registrado.</td></tr>
                    )}
                  </tbody>
                </table>
              </div>
            </Card>
          )}

          {activeTab === 'savings' && (
            <Card title="Minha Poupança">
              <div className="flex gap-2 mb-4">
                <button onClick={() => addSavingsTransaction('entrada')} className="bg-emerald-500 text-white px-4 py-2 rounded-lg flex items-center gap-2"><Plus className="w-4 h-4" /> Entrada</button>
                <button onClick={() => addSavingsTransaction('retirada')} className="bg-red-500 text-white px-4 py-2 rounded-lg flex items-center gap-2"><Plus className="w-4 h-4" /> Retirada</button>
                <button onClick={() => addSavingsTransaction('rendimento')} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2"><Plus className="w-4 h-4" /> Rendimento</button>
              </div>
