      <footer className="md:hidden fixed bottom-0 w-full bg-white dark:bg-slate-900 border-t dark:border-slate-800 p-2 grid grid-cols-6 gap-1 z-40">
        <button onClick={() => setActiveTab('dashboard')} className={`p-2 flex flex-col items-center ${activeTab === 'dashboard' ? 'text-primary-500' : 'text-slate-400'}`}><LayoutDashboard className="w-5 h-5" /><span className="text-[9px]">Painel</span></button>
        <button onClick={() => setActiveTab('monthly')} className={`p-2 flex flex-col items-center ${activeTab === 'monthly' ? 'text-primary-500' : 'text-slate-400'}`}><TableIcon className="w-5 h-5" /><span className="text-[9px]">Meses</span></button>
        <button onClick={() => setActiveTab('loans')} className={`p-2 flex flex-col items-center ${activeTab === 'loans' ? 'text-primary-500' : 'text-slate-400'}`}><CreditCard className="w-5 h-5" /><span className="text-[9px]">Emp.</span></button>
        <button onClick={() => setActiveTab('travel')} className={`p-2 flex flex-col items-center ${activeTab === 'travel' ? 'text-primary-500' : 'text-slate-400'}`}><Plane className="w-5 h-5" /><span className="text-[9px]">Viagem</span></button>
        <button onClick={() => setActiveTab('vehicle')} className={`p-2 flex flex-col items-center ${activeTab === 'vehicle' ? 'text-primary-500' : 'text-slate-400'}`}><Car className="w-5 h-5" /><span className="text-[9px]">Auto</span></button>
        <button onClick={() => setActiveTab('savings')} className={`p-2 flex flex-col items-center ${activeTab === 'savings' ? 'text-primary-500' : 'text-slate-400'}`}><PiggyBank className="w-5 h-5" /><span className="text-[9px]">Poupa</span></button>
      </footer>
    </div>
  );
}

export const formatCurrency = (value: number): string => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
  }).format(value);
};

export const MONTHS_BR = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

export const calculateTotalExpenses = (exp: any): number => {
  return (exp.inter || 0) + (exp.nubank || 0) + (exp.mPago || 0) + 
         (exp.agua || 0) + (exp.energia || 0) + (exp.outros || 0) + (exp.pix || 0);
};

export const calculateTotalIncome = (inc: any): number => {
  return (inc.salario || 0) + (inc.bonus || 0) + (inc.outros || 0) + (inc.recargaPay || 0);
};

export const getNextMonthSalary = (currentMonthName: string, allMonths: any[]): number => {
  const currentIdx = MONTHS_BR.indexOf(currentMonthName);
  if (currentIdx === -1) return 0;

  const nextIdx = (currentIdx + 1) % 12;
  const nextMonthName = MONTHS_BR[nextIdx];

  // Try to find the next month in the data set to get its salary
  const nextMonthData = allMonths.find(m => m.month === nextMonthName);
  return nextMonthData ? (nextMonthData.income.salario || 0) : 0;
};

