                <button onClick={() => addSavingsTransaction('retirada')} className="bg-red-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-red-600 transition-all shadow-md shadow-red-500/20"><Plus className="w-4 h-4" /> Retirada</button>
