                        <td className={`px-4 py-4 font-bold ${s.type === 'retirada' ? 'text-red-500' : 'text-emerald-500'}`}><input type="number" value={s.value} onChange={(e) => setData(prev => ({...prev, savings: prev.savings.map(item => item.id === s.id ? {...item, value: parseFloat(e.target.value) || 0} : item)}))} className="bg-transparent w-24 outline-none" /></td>
