);

export default function App() {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'monthly' | 'loans' | 'travel' | 'vehicle' | 'savings'>('dashboard');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [selectedMonthId, setSelectedMonthId] = useState<string | null>(null);

  const [data, setData] = useState<AppState>({
    months: [],
    loans: [],
    trips: [],
    vehicleExpenses: [],
    savings: []
  });

  const selectedMonth = useMemo(() => 
    data.months.find(m => m.id === selectedMonthId) || null, 
    [data.months, selectedMonthId]
  );

  useEffect(() => {
    const saved = localStorage.getItem('finance_app_data_v6');
    if (saved) {
      try {
        setData(JSON.parse(saved));
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('finance_app_data_v6', JSON.stringify(data));
  }, [data]);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const handleExcelImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const json = XLSX.utils.sheet_to_json(ws);

        const importedMonths: MonthData[] = json.map((row: any, idx: number) => ({
          id: Math.random().toString(36).substr(2, 9),
          month: row.Mes || row.Mês || MONTHS_BR[idx % 12],
          year: row.Ano || new Date().getFullYear(),
          expenses: {
            inter: row.Inter || 0,
            nubank: row.Nubank || 0,
            mPago: row.MPago || 0,
            agua: row.Agua || 0,
            energia: row.Energia || 0,
            outros: row.Outros_Gastos || 0,
            pix: row.Pix || 0,
          },
          income: {
            salario: row.Salario || row.Salário || 0,
            bonus: row.Bonus || row.Bônus || 0,
            outros: row.Outros_Ganhos || 0,
            recargaPay: row.RecargaPay || 0,
          }
        }));

        setData(prev => ({ ...prev, months: [...prev.months, ...importedMonths] }));
        alert(`${importedMonths.length} registros importados com sucesso!`);
      } catch (err) {
        alert("Erro ao ler o arquivo Excel. Verifique o formato das colunas.");
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleJSONImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        setData(JSON.parse(evt.target?.result as string));
        alert("Backup restaurado!");
      } catch (err) { alert("Erro no arquivo JSON."); }
    };
    reader.readAsText(file);
  };

  const addMonth = () => {
    const lastMonth = data.months[data.months.length - 1];
    let nextIndex = lastMonth ? (MONTHS_BR.indexOf(lastMonth.month) + 1) % 12 : new Date().getMonth();
    const monthName = MONTHS_BR[nextIndex];

    const newMonth: MonthData = {
      id: Math.random().toString(36).substr(2, 9),
      month: monthName,
      year: new Date().getFullYear(),
      expenses: { inter: 0, nubank: 0, mPago: 0, agua: 0, energia: 0, outros: 0, pix: 0 },
      income: { salario: 0, bonus: 0, outros: 0, recargaPay: 0 }
    };
    setData(prev => ({ ...prev, months: [...prev.months, newMonth] }));
    setSelectedMonthId(newMonth.id);
  };

  const updateMonthField = (id: string, category: 'expenses' | 'income', field: string, value: string) => {
    const num = value === "" ? 0 : parseFloat(value);
    setData(prev => ({
      ...prev,
      months: prev.months.map(m => m.id === id ? {
        ...m,
        [category]: { ...m[category], [field]: isNaN(num) ? 0 : num }
      } : m)
    }));
  };

  const handleDeleteMonth = (id: string) => {
    if (window.confirm("Deseja realmente excluir todos os dados deste mês?")) {
      setData(prev => ({
        ...prev,
        months: prev.months.filter(m => m.id !== id)
      }));
      setSelectedMonthId(null);
    }
  };

  const addVehicleExpense = (type: VehicleType) => {
    const currentMonth = data.months[data.months.length - 1]?.month || MONTHS_BR[new Date().getMonth()];
    setData(prev => ({ 
      ...prev, 
      vehicleExpenses: [...prev.vehicleExpenses, {
        id: Math.random().toString(36).substr(2, 9),
        type,
        category: VehicleCategory.FUEL,
        description: "Novo lançamento",
        value: 0,
        month: currentMonth
      }] 
    }));
  };

  const addSavingsTransaction = (type: 'entrada' | 'retirada' | 'rendimento') => {
    const currentMonth = data.months[data.months.length - 1]?.month || MONTHS_BR[new Date().getMonth()];
    setData(prev => ({ 
      ...prev, 
      savings: [...prev.savings, {
        id: Math.random().toString(36).substr(2, 9),
        type,
        value: 0,
        description: type.charAt(0).toUpperCase() + type.slice(1),
        month: currentMonth
      }] 
    }));
  };

  const chartData = useMemo(() => {
    return data.months.map((m) => {
      const expenses = calculateTotalExpenses(m.expenses);
      const nextSal = getNextMonthSalary(m.month, data.months);
      const incomeTotal = calculateTotalIncome(m.income);
      return {
        name: m.month,
        gastos: expenses,
        ganhos: incomeTotal,
        balancoProx: nextSal - expenses
      };
    });
  }, [data.months]);

  return (
    <div className="min-h-screen transition-colors duration-200 dark:bg-slate-900 bg-slate-50 flex flex-col">
      <header className="sticky top-0 z-40 w-full bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b dark:border-slate-800 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-primary-500 rounded-xl flex items-center justify-center shadow-lg shadow-primary-500/30">
              <PiggyBank className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold dark:text-white hidden sm:block">FinanceMaster</h1>
          </div>

          <div className="flex items-center gap-2">
            <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400">
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
            <div className="h-6 w-px bg-slate-200 dark:bg-slate-700 mx-2"></div>
            <label className="cursor-pointer p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400" title="Importar Excel">
              <FileSpreadsheet className="w-5 h-5" />
              <input type="file" className="hidden" accept=".xlsx,.xls" onChange={handleExcelImport} />
            </label>
            <label className="cursor-pointer p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400" title="Restaurar Backup JSON">
              <Upload className="w-5 h-5" />
              <input type="file" className="hidden" accept=".json" onChange={handleJSONImport} />
            </label>
            <button onClick={() => {
              const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
              const url = URL.createObjectURL(blob);
              const a = document.createElement('a');
              a.href = url; a.download = 'finance_data.json'; a.click();
            }} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400" title="Exportar Backup">
              <Download className="w-5 h-5" />
            </button>
            <button onClick={() => window.confirm("Zerar todos os dados?") && setData({ months: [], loans: [], trips: [], vehicleExpenses: [], savings: [] })} className="p-2 rounded-lg hover:bg-red-50 text-red-600">
              <Trash2 className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl w-full mx-auto p-4 md:p-6 pb-24">
        <div className="flex items-center gap-2 overflow-x-auto pb-4 mb-6 custom-scrollbar border-b dark:border-slate-800">
          <TabButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard className="w-5 h-5" />} label="Painel" />
          <TabButton active={activeTab === 'monthly'} onClick={() => setActiveTab('monthly')} icon={<TableIcon className="w-5 h-5" />} label="Mensal" />
          <TabButton active={activeTab === 'loans'} onClick={() => setActiveTab('loans')} icon={<CreditCard className="w-5 h-5" />} label="Empréstimos" />
          <TabButton active={activeTab === 'travel'} onClick={() => setActiveTab('travel')} icon={<Plane className="w-5 h-5" />} label="Viagens" />
          <TabButton active={activeTab === 'vehicle'} onClick={() => setActiveTab('vehicle')} icon={<Car className="w-5 h-5" />} label="Veículos" />
          <TabButton active={activeTab === 'savings'} onClick={() => setActiveTab('savings')} icon={<PiggyBank className="w-5 h-5" />} label="Poupança" />
        </div>

        <div className="space-y-6">
          {activeTab === 'dashboard' && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <Card title="Resumo Financeiro Mensal" className="md:col-span-3 h-[400px]">
                {data.months.length === 0 ? <div className="h-full flex items-center justify-center text-slate-400 italic">Sem dados. Adicione um lançamento mensal para começar.</div> : (
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chartData}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
                      <XAxis dataKey="name" stroke={isDarkMode ? '#94a3b8' : '#64748b'} />
                      <YAxis stroke={isDarkMode ? '#94a3b8' : '#64748b'} />
                      <Tooltip contentStyle={{ backgroundColor: isDarkMode ? '#1e293b' : '#fff', borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} />
                      <Legend />
                      <Bar dataKey="gastos" fill="#f43f5e" name="Gastos do Mês" radius={[6,6,0,0]} />
                      <Bar dataKey="ganhos" fill="#10b981" name="Ganhos do Mês" radius={[6,6,0,0]} />
                    </BarChart>
                  </ResponsiveContainer>
                )}
              </Card>
            </div>
          )}

          {activeTab === 'monthly' && (
            <Card title="Controle Mensal">
              <div className="mb-4 flex justify-between items-center">
                <p className="text-xs text-slate-500 italic">* Gastos de um mês são comparados com o salário do mês seguinte.</p>
                <button onClick={addMonth} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-primary-600 transition-all shadow-md shadow-primary-500/20">
                  <Plus className="w-4 h-4" /> Novo Mês
                </button>
              </div>
              <div className="overflow-x-auto border dark:border-slate-700 rounded-xl shadow-sm">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-700 text-slate-500 uppercase font-semibold">
                    <tr>
                      <th className="px-4 py-3">Mês</th>
                      <th className="px-4 py-3">Gastos Totais</th>
                      <th className="px-4 py-3">Ganhos Totais</th>
                      <th className="px-4 py-3">Balanço (Próx. Sal)</th>
                      <th className="px-4 py-3 text-right">Editar</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y dark:divide-slate-700">
                    {data.months.map((m) => {
                      const totalExp = calculateTotalExpenses(m.expenses);
                      const totalInc = calculateTotalIncome(m.income);
                      const nextSal = getNextMonthSalary(m.month, data.months);
                      const balanceProx = nextSal - totalExp;

                      return (
                        <tr key={m.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 cursor-pointer transition-colors" onClick={() => setSelectedMonthId(m.id)}>
                          <td className="px-4 py-4 font-semibold dark:text-white">{m.month}</td>
                          <td className="px-4 py-4 text-red-500 font-medium">{formatCurrency(totalExp)}</td>
                          <td className="px-4 py-4 text-emerald-500 font-medium">{formatCurrency(totalInc)}</td>
                          <td className={`px-4 py-4 font-bold ${balanceProx >= 0 ? 'text-emerald-500' : 'text-red-500'}`}>
                            {nextSal > 0 ? formatCurrency(balanceProx) : <span className="text-slate-400 text-xs font-normal">Falta Sal. {MONTHS_BR[(MONTHS_BR.indexOf(m.month)+1)%12]}</span>}
                          </td>
                          <td className="px-4 py-4 text-right"><ChevronRight className="w-5 h-5 text-slate-300 ml-auto" /></td>
                        </tr>
                      );
                    })}
                    {data.months.length === 0 && (
                      <tr><td colSpan={5} className="px-4 py-12 text-center text-slate-400 italic">Nenhum mês registrado. Clique em "Novo Mês" para começar.</td></tr>
                    )}
                  </tbody>
                </table>
              </div>
            </Card>
          )}

          {activeTab === 'loans' && (
            <Card title="Empréstimos">
              <div className="mb-4"><button onClick={() => setData(prev => ({...prev, loans: [...prev.loans, { id: Math.random().toString(36).substr(2,9), description: "Novo Empréstimo", totalValue: 0, installments: 1, paidInstallments: 0, installmentValue: 0, interestMonthly: 0 }]}))} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2"><Plus className="w-4 h-4" /> Adicionar</button></div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {data.loans.map(loan => (
                  <div key={loan.id} className="p-5 border dark:border-slate-700 rounded-2xl space-y-4 relative group bg-white dark:bg-slate-800 shadow-sm">
                    <button onClick={(e) => { e.stopPropagation(); setData(prev => ({...prev, loans: prev.loans.filter(l => l.id !== loan.id)})); }} className="absolute top-3 right-3 text-red-400 opacity-0 group-hover:opacity-100 transition-opacity p-2 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg"><Trash2 className="w-4 h-4"/></button>
                    <input type="text" value={loan.description} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, description: e.target.value} : l)}))} className="bg-transparent font-bold w-full dark:text-white outline-none border-b border-transparent focus:border-primary-500 text-lg" placeholder="Descrição do Empréstimo" />
                    <div className="grid grid-cols-2 gap-4 text-xs">
                      <div className="space-y-1"><label className="text-slate-400 uppercase font-semibold">Valor Total</label><input type="number" step="any" value={loan.totalValue === 0 ? "" : loan.totalValue} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, totalValue: parseFloat(e.target.value) || 0} : l)}))} className="w-full p-2.5 bg-slate-50 dark:bg-slate-900 rounded-xl dark:text-white border dark:border-slate-700 outline-none focus:ring-1 focus:ring-primary-500" /></div>
                      <div className="space-y-1"><label className="text-slate-400 uppercase font-semibold">Valor Parcela</label><input type="number" step="any" value={loan.installmentValue === 0 ? "" : loan.installmentValue} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, installmentValue: parseFloat(e.target.value) || 0} : l)}))} className="w-full p-2.5 bg-slate-50 dark:bg-slate-900 rounded-xl dark:text-white border dark:border-slate-700 outline-none focus:ring-1 focus:ring-primary-500" /></div>
                      <div className="space-y-1"><label className="text-slate-400 uppercase font-semibold">Parcelas Totais</label><input type="number" value={loan.installments === 0 ? "" : loan.installments} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, installments: parseInt(e.target.value) || 0} : l)}))} className="w-full p-2.5 bg-slate-50 dark:bg-slate-900 rounded-xl dark:text-white border dark:border-slate-700 outline-none focus:ring-1 focus:ring-primary-500" /></div>
                      <div className="space-y-1"><label className="text-slate-400 uppercase font-semibold">Pagas</label><input type="number" value={loan.paidInstallments === 0 ? "" : loan.paidInstallments} onChange={(e) => setData(prev => ({...prev, loans: prev.loans.map(l => l.id === loan.id ? {...l, paidInstallments: parseInt(e.target.value) || 0} : l)}))} className="w-full p-2.5 bg-slate-50 dark:bg-slate-900 rounded-xl dark:text-white border dark:border-slate-700 outline-none focus:ring-1 focus:ring-primary-500" /></div>
                    </div>
                  </div>
                ))}
                {data.loans.length === 0 && <div className="col-span-2 text-center py-10 text-slate-400 italic">Nenhum empréstimo registrado.</div>}
              </div>
            </Card>
          )}

          {activeTab === 'vehicle' && (
            <Card title="Despesas com Veículos">
              <div className="flex gap-2 mb-4">
                <button onClick={() => addVehicleExpense(VehicleType.CAR)} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-all hover:scale-105 active:scale-95 shadow-md shadow-primary-500/20"><Plus className="w-4 h-4" /> Gasto Carro</button>
                <button onClick={() => addVehicleExpense(VehicleType.MOTORCYCLE)} className="bg-amber-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-all hover:scale-105 active:scale-95 shadow-md shadow-amber-500/20"><Plus className="w-4 h-4" /> Gasto Moto</button>
              </div>
              <div className="overflow-x-auto border dark:border-slate-700 rounded-2xl shadow-sm">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-700 text-slate-500 uppercase tracking-tight">
                    <tr>
                      <th className="px-4 py-4">Veículo</th>
                      <th className="px-4 py-4">Tipo Gasto</th>
                      <th className="px-4 py-4">Mês do Gasto</th>
                      <th className="px-4 py-4">Descrição</th>
                      <th className="px-4 py-4">Valor</th>
                      <th className="px-4 py-4 text-center">Ação</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y dark:divide-slate-700">
                    {data.vehicleExpenses.map(exp => (
                      <tr key={exp.id} className="dark:text-white transition-colors hover:bg-slate-50 dark:hover:bg-slate-800/30">
                        <td className="px-4 py-4">
                           <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase ${exp.type === VehicleType.CAR ? 'bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400' : 'bg-orange-100 text-orange-600 dark:bg-orange-900/30 dark:text-orange-400'}`}>
                              {exp.type}
                           </span>
                        </td>
                        <td className="px-4 py-4">
                          <select 
                            value={exp.category || VehicleCategory.FUEL} 
                            onChange={(e) => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.map(v => v.id === exp.id ? {...v, category: e.target.value as VehicleCategory} : v)}))} 
                            className="bg-slate-100 dark:bg-slate-700 rounded-lg px-3 py-1.5 outline-none text-xs font-medium dark:text-slate-200 border border-transparent focus:border-primary-500"
                          >
                            {Object.values(VehicleCategory).map(cat => <option key={cat} value={cat}>{cat}</option>)}
                          </select>
                        </td>
                        <td className="px-4 py-4">
                          <select 
                            value={exp.month} 
                            onChange={(e) => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.map(v => v.id === exp.id ? {...v, month: e.target.value} : v)}))} 
                            className="bg-transparent dark:bg-slate-800 outline-none font-medium cursor-pointer hover:text-primary-500"
                          >
                            {MONTHS_BR.map(m => <option key={m} value={m}>{m}</option>)}
                          </select>
                        </td>
                        <td className="px-4 py-4"><input type="text" value={exp.description} onChange={(e) => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.map(v => v.id === exp.id ? {...v, description: e.target.value} : v)}))} className="bg-transparent w-full outline-none focus:border-b border-primary-500" placeholder="Ex: Óleo, Pneu..." /></td>
                        <td className="px-4 py-4 font-bold text-primary-500"><input type="number" step="any" value={exp.value === 0 ? "" : exp.value} onChange={(e) => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.map(v => v.id === exp.id ? {...v, value: parseFloat(e.target.value) || 0} : v)}))} className="bg-transparent w-24 outline-none font-bold" /></td>
                        <td className="px-4 py-4 text-center"><button onClick={() => setData(prev => ({...prev, vehicleExpenses: prev.vehicleExpenses.filter(v => v.id !== exp.id)}))} className="text-red-400 hover:text-red-600 transition-transform hover:scale-110 p-2"><Trash2 className="w-4 h-4" /></button></td>
                      </tr>
                    ))}
                    {data.vehicleExpenses.length === 0 && (
                      <tr><td colSpan={6} className="px-4 py-12 text-center text-slate-400 italic font-medium">Sem lançamentos de veículos.</td></tr>
                    )}
                  </tbody>
                </table>
              </div>
            </Card>
          )}

          {activeTab === 'savings' && (
            <Card title="Poupança e Rendimentos">
              <div className="flex gap-2 mb-4">
                <button onClick={() => addSavingsTransaction('entrada')} className="bg-emerald-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-emerald-600 transition-all shadow-md shadow-emerald-500/20"><Plus className="w-4 h-4" /> Entrada</button>
                <button onClick={() => addSavingsTransaction('retirada')} className="bg-red-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-red-600 transition-all shadow-md shadow-red-500/20"><Plus className="w-4 h-4" /> Retirada</button>
                <button onClick={() => addSavingsTransaction('rendimento')} className="bg-primary-500 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-primary-600 transition-all shadow-md shadow-primary-500/20"><Plus className="w-4 h-4" /> Rendimento</button>
              </div>
              <div className="overflow-x-auto border dark:border-slate-700 rounded-2xl">
                <table className="w-full text-left text-sm">
                  <thead className="bg-slate-50 dark:bg-slate-800/50 border-b dark:border-slate-700 text-slate-500 uppercase">
                    <tr><th className="px-4 py-4">Movimentação</th><th className="px-4 py-4">Mês Referência</th><th className="px-4 py-4">Descrição</th><th className="px-4 py-4">Valor</th><th className="px-4 py-4 text-center">Ação</th></tr>
                  </thead>
                  <tbody className="divide-y dark:divide-slate-700">
                    {data.savings.map(s => (
                      <tr key={s.id} className="dark:text-white transition-colors hover:bg-slate-50 dark:hover:bg-slate-800/30">
                        <td className="px-4 py-4">
                          <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${s.type === 'entrada' ? 'bg-emerald-100 text-emerald-600' : s.type === 'retirada' ? 'bg-red-100 text-red-600' : 'bg-primary-100 text-primary-600'}`}>
                             {s.type}
                          </span>
                        </td>
                        <td className="px-4 py-4">
                          <select value={s.month} onChange={(e) => setData(prev => ({...prev, savings: prev.savings.map(item => item.id === s.id ? {...item, month: e.target.value} : item)}))} className="bg-transparent dark:bg-slate-800 outline-none font-medium">
                            {MONTHS_BR.map(m => <option key={m} value={m}>{m}</option>)}
                          </select>
                        </td>
                        <td className="px-4 py-4"><input type="text" value={s.description} onChange={(e) => setData(prev => ({...prev, savings: prev.savings.map(item => item.id === s.id ? {...item, description: e.target.value} : item)}))} className="bg-transparent w-full outline-none focus:border-b border-primary-500" /></td>
                        <td className={`px-4 py-4 font-bold ${s.type === 'retirada' ? 'text-red-500' : 'text-emerald-500'}`}><input type="number" step="any" value={s.value === 0 ? "" : s.value} onChange={(e) => setData(prev => ({...prev, savings: prev.savings.map(item => item.id === s.id ? {...item, value: parseFloat(e.target.value) || 0} : item)}))} className="bg-transparent w-24 outline-none" /></td>
                        <td className="px-4 py-4 text-center"><button onClick={() => setData(prev => ({...prev, savings: prev.savings.filter(item => item.id !== s.id)}))} className="text-red-400 hover:text-red-600 p-2"><Trash2 className="w-4 h-4" /></button></td>
                      </tr>
                    ))}
                    {data.savings.length === 0 && (
                      <tr><td colSpan={5} className="px-4 py-12 text-center text-slate-400 italic">Nenhum registro de poupança.</td></tr>
                    )}
                  </tbody>
                </table>
              </div>
            </Card>
          )}

          {activeTab === 'travel' && (
            <Card title="Planejamento de Viagens">
              <div className="mb-6"><button onClick={() => setData(prev => ({...prev, trips: [...prev.trips, { id: Math.random().toString(36).substr(2,9), destination: "Nova Viagem", month: MONTHS_BR[new Date().getMonth()], carRental: 0, fuel: 0, food: 0, others: 0, creditCard: 0, pix: 0 }] }))} className="bg-primary-500 text-white px-6 py-2.5 rounded-xl flex items-center gap-2 hover:bg-primary-600 transition-all shadow-lg shadow-primary-500/20 active:scale-95"><Plus className="w-5 h-5" /> Registrar Nova Viagem</button></div>
              <div className="grid grid-cols-1 gap-6">
                {data.trips.map(trip => (
                  <div key={trip.id} className="p-6 border dark:border-slate-700 rounded-2xl shadow-sm bg-white dark:bg-slate-800 relative group">
                    <button onClick={() => setData(prev => ({...prev, trips: prev.trips.filter(t => t.id !== trip.id)}))} className="absolute top-4 right-4 text-red-400 p-2 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl transition-all opacity-0 group-hover:opacity-100"><Trash2 className="w-5 h-5"/></button>
                    <div className="flex flex-wrap items-center gap-6 mb-6">
                       <div className="flex-1 min-w-[300px] flex items-center gap-4">
                          <input type="text" value={trip.destination} onChange={(e) => setData(prev => ({...prev, trips: prev.trips.map(t => t.id === trip.id ? {...t, destination: e.target.value} : t)}))} className="bg-transparent font-bold dark:text-white outline-none border-b-2 border-slate-100 dark:border-slate-700 focus:border-primary-500 text-2xl w-full py-1 transition-colors" placeholder="Ex: Rio de Janeiro" />
                          <div className="flex items-center gap-2 bg-slate-50 dark:bg-slate-900 px-3 py-1.5 rounded-xl border dark:border-slate-700">
                             <label className="text-[10px] uppercase font-bold text-slate-400">Mês</label>
                             <select 
                                value={trip.month} 
                                onChange={(e) => setData(prev => ({...prev, trips: prev.trips.map(t => t.id === trip.id ? {...t, month: e.target.value} : t)}))}
                                className="bg-transparent outline-none font-bold text-sm dark:text-white cursor-pointer"
                             >
                                {MONTHS_BR.map(m => <option key={m} value={m}>{m}</option>)}
                             </select>
                          </div>
                       </div>
                    </div>
                    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-5">
                      {[
                        { label: 'Aluguel Carro', field: 'carRental' },
                        { label: 'Combustível', field: 'fuel' },
                        { label: 'Alimentação', field: 'food' },
                        { label: 'Outros', field: 'others' },
                        { label: 'Cartão Crédito', field: 'creditCard' },
                        { label: 'Pix / Dinheiro', field: 'pix' }
                      ].map(f => (
                        <div key={f.field} className="space-y-1.5">
                          <label className="text-slate-400 text-[10px] uppercase font-bold tracking-wider">{f.label}</label>
                          <input 
                            type="number" 
                            step="any"
                            value={(trip as any)[f.field] === 0 ? "" : (trip as any)[f.field]} 
                            onChange={(e) => setData(prev => ({...prev, trips: prev.trips.map(t => t.id === trip.id ? {...t, [f.field]: parseFloat(e.target.value) || 0} : t)}))} 
                            className="w-full p-2.5 bg-slate-50 dark:bg-slate-900 border dark:border-slate-700 rounded-xl dark:text-white outline-none focus:ring-1 focus:ring-primary-500 font-medium" 
                          />
                        </div>
                      ))}
                    </div>
                    <div className="mt-6 flex justify-between items-center p-4 bg-primary-50 dark:bg-primary-900/10 rounded-2xl border border-primary-100 dark:border-primary-900/20">
                       <span className="text-primary-700 dark:text-primary-400 font-bold uppercase text-xs tracking-widest">Custo Total da Viagem</span>
                       <span className="text-2xl font-black text-primary-600 dark:text-primary-400">
                          {formatCurrency(trip.carRental + trip.fuel + trip.food + trip.others + trip.creditCard + trip.pix)}
                       </span>
                    </div>
                  </div>
                ))}
              </div>
            </Card>
          )}
        </div>
      </main>

      <Modal isOpen={!!selectedMonthId} onClose={() => setSelectedMonthId(null)} title={`Lançamentos: ${selectedMonth?.month || ''}`}>
        {selectedMonth && (
          <div className="space-y-8">
            <div className="flex items-center gap-6 p-5 bg-slate-50 dark:bg-slate-900/50 rounded-2xl border dark:border-slate-700">
               <label className="text-sm font-black dark:text-slate-300 uppercase tracking-widest">Mudar Mês:</label>
               <select 
                 value={selectedMonth.month} 
                 onChange={(e) => {
                    const newMonthName = e.target.value;
                    setData(prev => ({
                      ...prev,
                      months: prev.months.map(m => m.id === selectedMonth.id ? { ...m, month: newMonthName } : m)
                    }));
                 }}
                 className="flex-1 bg-white dark:bg-slate-800 rounded-xl px-5 py-3 outline-none dark:text-white border-2 border-transparent focus:border-primary-500 font-bold text-lg shadow-sm"
               >
                 {MONTHS_BR.map(m => <option key={m} value={m}>{m}</option>)}
               </select>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="space-y-4">
                <h4 className="font-black text-red-500 border-b-2 border-red-500/20 pb-2 flex items-center gap-2 uppercase tracking-widest text-sm">Saídas (Gastos)</h4>
                <div className="grid grid-cols-2 gap-4">
                  {Object.keys(selectedMonth.expenses).map(key => (
                    <div key={key} className="space-y-1">
                      <label className="text-[10px] text-slate-400 uppercase font-black tracking-widest">{key}</label>
                      <input 
                        type="number" 
                        step="any"
                        value={(selectedMonth.expenses as any)[key] === 0 ? "" : (selectedMonth.expenses as any)[key]} 
                        onChange={(e) => updateMonthField(selectedMonth.id, 'expenses', key, e.target.value)} 
                        className="w-full p-3 bg-white dark:bg-slate-700 rounded-xl dark:text-white outline-none focus:ring-2 focus:ring-red-500/30 border border-slate-100 dark:border-slate-600 font-bold" 
                      />
                    </div>
                  ))}
                </div>
                <div className="p-4 bg-red-50 dark:bg-red-900/10 rounded-xl text-center">
                    <p className="text-xs text-red-400 font-bold uppercase mb-1">Total Despesas</p>
                    <p className="text-2xl font-black text-red-600">{formatCurrency(calculateTotalExpenses(selectedMonth.expenses))}</p>
                </div>
              </div>

              <div className="space-y-4">
                <h4 className="font-black text-emerald-500 border-b-2 border-emerald-500/20 pb-2 flex items-center gap-2 uppercase tracking-widest text-sm">Entradas (Ganhos)</h4>
                <div className="grid grid-cols-2 gap-4">
                  {Object.keys(selectedMonth.income).map(key => (
                    <div key={key} className="space-y-1">
                      <label className="text-[10px] text-slate-400 uppercase font-black tracking-widest">{key}</label>
                      <input 
                        type="number" 
                        step="any"
                        value={(selectedMonth.income as any)[key] === 0 ? "" : (selectedMonth.income as any)[key]} 
                        onChange={(e) => updateMonthField(selectedMonth.id, 'income', key, e.target.value)} 
                        className="w-full p-3 bg-white dark:bg-slate-700 rounded-xl dark:text-white outline-none focus:ring-2 focus:ring-emerald-500/30 border border-slate-100 dark:border-slate-600 font-bold" 
                      />
                    </div>
                  ))}
                </div>
                <div className="p-4 bg-emerald-50 dark:bg-emerald-900/10 rounded-xl text-center">
                    <p className="text-xs text-emerald-400 font-bold uppercase mb-1">Total Receitas</p>
                    <p className="text-2xl font-black text-emerald-600">{formatCurrency(calculateTotalIncome(selectedMonth.income))}</p>
                </div>
              </div>
            </div>

            <div className="p-6 bg-slate-900 dark:bg-black rounded-3xl flex flex-wrap gap-6 justify-between items-center text-white">
              <div className="space-y-1">
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Balanço do Mês</p>
                <p className={`text-3xl font-black ${calculateTotalIncome(selectedMonth.income) - calculateTotalExpenses(selectedMonth.expenses) >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                   {formatCurrency(calculateTotalIncome(selectedMonth.income) - calculateTotalExpenses(selectedMonth.expenses))}
                </p>
              </div>
              <button 
                type="button"
                onClick={() => handleDeleteMonth(selectedMonth.id)} 
                className="bg-red-500 hover:bg-red-600 text-white px-6 py-3 rounded-2xl flex items-center gap-2 transition-all font-bold shadow-lg shadow-red-500/20 active:scale-95 group"
              >
                <Trash2 className="w-5 h-5 group-hover:scale-110 transition-transform" /> 
                <span>Excluir Mês</span>
              </button>
            </div>
          </div>
        )}
      </Modal>

      <footer className="md:hidden fixed bottom-0 w-full bg-white dark:bg-slate-900 border-t dark:border-slate-800 p-2 grid grid-cols-6 gap-1 z-40 shadow-[0_-10px_15px_-3px_rgba(0,0,0,0.1)]">
        <button onClick={() => setActiveTab('dashboard')} className={`p-2 flex flex-col items-center transition-colors ${activeTab === 'dashboard' ? 'text-primary-500' : 'text-slate-400'}`}><LayoutDashboard className="w-5 h-5" /><span className="text-[9px] font-bold">Painel</span></button>
        <button onClick={() => setActiveTab('monthly')} className={`p-2 flex flex-col items-center transition-colors ${activeTab === 'monthly' ? 'text-primary-500' : 'text-slate-400'}`}><TableIcon className="w-5 h-5" /><span className="text-[9px] font-bold">Lançamentos</span></button>
        <button onClick={() => setActiveTab('loans')} className={`p-2 flex flex-col items-center transition-colors ${activeTab === 'loans' ? 'text-primary-500' : 'text-slate-400'}`}><CreditCard className="w-5 h-5" /><span className="text-[9px] font-bold">Emp.</span></button>
        <button onClick={() => setActiveTab('travel')} className={`p-2 flex flex-col items-center transition-colors ${activeTab === 'travel' ? 'text-primary-500' : 'text-slate-400'}`}><Plane className="w-5 h-5" /><span className="text-[9px] font-bold">Viagem</span></button>
        <button onClick={() => setActiveTab('vehicle')} className={`p-2 flex flex-col items-center transition-colors ${activeTab === 'vehicle' ? 'text-primary-500' : 'text-slate-400'}`}><Car className="w-5 h-5" /><span className="text-[9px] font-bold">Auto</span></button>
        <button onClick={() => setActiveTab('savings')} className={`p-2 flex flex-col items-center transition-colors ${activeTab === 'savings' ? 'text-primary-500' : 'text-slate-400'}`}><PiggyBank className="w-5 h-5" /><span className="text-[9px] font-bold">Poupa</span></button>
      </footer>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Table as TableIcon, 
  CreditCard, 
  Plane, 
  Car, 
  PiggyBank, 
  Plus, 
  Download, 
  Upload, 
  Sun, 
  Moon,
  ChevronRight,
  X,
  Trash2,
  FileSpreadsheet
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer
} from 'recharts';
import { 
  MonthData, 
  Loan, 
  TripExpense, 
  VehicleExpense, 
  SavingsTransaction, 
  AppState, 
  VehicleType,
  VehicleCategory
} from './types';
import { 
  formatCurrency, 
  MONTHS_BR, 
  calculateTotalExpenses, 
  calculateTotalIncome,
  getNextMonthSalary
} from './utils';

// Declare XLSX from global script
declare const XLSX: any;

const Modal: React.FC<{ isOpen: boolean; onClose: () => void; title: string; children: React.ReactNode }> = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        <div className="flex items-center justify-between p-6 border-b dark:border-slate-700">
          <h2 className="text-xl font-bold dark:text-white">{title}</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-5 h-5 dark:text-slate-400" />
          </button>
        </div>
        <div className="p-6 overflow-y-auto custom-scrollbar">
          {children}
        </div>
      </div>
    </div>
  );
};

const TabButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button
    onClick={onClick}
    className={`flex items-center gap-2 px-4 py-3 rounded-lg font-medium transition-all duration-200 ${
      active 
        ? 'bg-primary-500 text-white shadow-lg shadow-primary-500/30' 
        : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
    }`}
  >
    {icon}
    <span className="hidden md:inline">{label}</span>
  </button>
);

const Card: React.FC<{ title: string; children: React.ReactNode; className?: string }> = ({ title, children, className = "" }) => (
  <div className={`bg-white dark:bg-slate-800 p-6 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm ${className}`}>
    <h3 className="text-sm font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4">{title}</h3>
    {children}
  </div>
);

export default function App() {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'monthly' | 'loans' | 'travel' | 'vehicle' | 'savings'>('dashboard');
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [selectedMonthId, setSelectedMonthId] = useState<string | null>(null);

  const [data, setData] = useState<AppState>({
    months: [],
    loans: [],
    trips: [],
    vehicleExpenses: [],
    savings: []
  });

  const selectedMonth = useMemo(() => 
    data.months.find(m => m.id === selectedMonthId) || null, 
    [data.months, selectedMonthId]
  );

  useEffect(() => {
    const saved = localStorage.getItem('finance_app_data_v7');
    if (saved) {
      try {
        setData(JSON.parse(saved));
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('finance_app_data_v7', JSON.stringify(data));
  }, [data]);

  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  const handleExcelImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const json = XLSX.utils.sheet_to_json(ws);

        const importedMonths: MonthData[] = json.map((row: any, idx: number) => ({
          id: Math.random().toString(36).substr(2, 9),
          month: row.Mes || row.Mês || MONTHS_BR[idx % 12],
          year: row.Ano || new Date().getFullYear(),
          expenses: {
            inter: Number(row.Inter) || 0,
            nubank: Number(row.Nubank) || 0,
            mPago: Number(row.MPago) || 0,
            agua: Number(row.Agua) || 0,
            energia: Number(row.Energia) || 0,
            outros: Number(row.Outros_Gastos) || 0,
            pix: Number(row.Pix) || 0,
          },
          income: {
            salario: Number(row.Salario || row.Salário) || 0,
            bonus: Number(row.Bonus || row.Bônus) || 0,
            outros: Number(row.Outros_Ganhos) || 0,
            recargaPay: Number(row.RecargaPay) || 0,
          }
        }));

        setData(prev => ({ ...prev, months: [...prev.months, ...importedMonths] }));
        alert(`${importedMonths.length} registros importados!`);
      } catch (err) {
        alert("Erro ao ler Excel.");
      }
    };
    reader.readAsBinaryString(file);
  };

  const handleJSONImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        setData(JSON.parse(evt.target?.result as string));
        alert("Backup restaurado!");
      } catch (err) { alert("Erro no arquivo JSON."); }
    };
    reader.readAsText(file);
  };

  const addMonth = () => {
    const lastMonth = data.months[data.months.length - 1];
    let nextIndex = lastMonth ? (MONTHS_BR.indexOf(lastMonth.month) + 1) % 12 : new Date().getMonth();
    const monthName = MONTHS_BR[nextIndex];

    const newMonth: MonthData = {
      id: Math.random().toString(36).substr(2, 9),
      month: monthName,
      year: new Date().getFullYear(),
      expenses: { inter: 0, nubank: 0, mPago: 0, agua: 0, energia: 0, outros: 0, pix: 0 },
      income: { salario: 0, bonus: 0, outros: 0, recargaPay: 0 }
    };
    setData(prev => ({ ...prev, months: [...prev.months, newMonth] }));
    setSelectedMonthId(newMonth.id);
  };

  const updateMonthField = (id: string, category: 'expenses' | 'income', field: string, value: string) => {
    const num = value === "" ? 0 : parseFloat(value);
    setData(prev => ({
      ...prev,
      months: prev.months.map(m => m.id === id ? {
        ...m,
        [category]: { ...m[category], [field]: isNaN(num) ? 0 : num }
      } : m)
    }));
  };

  const handleDeleteMonth = (id: string) => {
    if (window.confirm("Deseja realmente excluir todos os dados deste mês?")) {
      // Importante: Limpar a seleção antes de remover dos dados para evitar conflitos de renderização
      setSelectedMonthId(null);
      setData(prev => ({
        ...prev,
        months: prev.months.filter(m => m.id !== id)
      }));
    }
  };

  const addVehicleExpense = (type: VehicleType) => {
    const currentMonth = data.months[data.months.length - 1]?.month || MONTHS_BR[new Date().getMonth()];
    setData(prev => ({ 
      ...prev, 
      vehicleExpenses: [...prev.vehicleExpenses, {
        id: Math.random().toString(36).substr(2, 9),
        type,
        category: VehicleCategory.FUEL,
        description: "Novo lançamento",
        value: 0,
        month: currentMonth
      }] 
    }));
  };

  const addSavingsTransaction = (type: 'entrada' | 'retirada' | 'rendimento') => {
    const currentMonth = data.months[data.months.length - 1]?.month || MONTHS_BR[new Date().getMonth()];
    setData(prev => ({ 
      ...prev, 
      savings: [...prev.savings, {
        id: Math.random().toString(36).substr(2, 9),
        type,
        value: 0,
        description: type.charAt(0).toUpperCase() + type.slice(1),
        month: currentMonth
      }] 
    }));
  };

  const chartData = useMemo(() => {
    return data.months.map((m) => {
      const expenses = calculateTotalExpenses(m.expenses);
      const nextSal = getNextMonthSalary(m.month, data.months);
      const incomeTotal = calculateTotalIncome(m.income);
      return {
        name: m.month,
        gastos: expenses,
        ganhos: incomeTotal,
        balancoProx: nextSal - expenses
      };
    });
  }, [data.months]);

  return (
    <div className="min-h-screen transition-colors duration-200 dark:bg-slate-900 bg-slate-50 flex flex-col">
      <header className="sticky top-0 z-40 w-full bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b dark:border-slate-800 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-primary-500 rounded-xl flex items-center justify-center shadow-lg shadow-primary-500/30">
              <PiggyBank className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold dark:text-white hidden sm:block">FinanceMaster</h1>
          </div>

          <div className="flex items-center gap-2">
            <button onClick={() => setIsDarkMode(!isDarkMode)} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400">
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
            <div className="h-6 w-px bg-slate-200 dark:bg-slate-700 mx-2"></div>
            <label className="cursor-pointer p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400" title="Importar Excel">
              <FileSpreadsheet className="w-5 h-5" />
              <input type="file" className="hidden" accept=".xlsx,.xls" onChange={handleExcelImport} />
            </label>
            <label className="cursor-pointer p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-600 dark:text-slate-400" title="Restaurar Backup JSON">
              <Upload className="w-5 h-5" />
              <input type="file" className="hidden" accept=".json" onChange={handleJSONImport} />
            </label>
            <button onClick={() => {
              const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
              const url = URL.createObjectURL(blob);
              const a = document.createElement('a');
              a.href = url; a.download = 'finance_data.json'; a.click();
