                      <select value={trip.month} onChange={(e) => setData(prev => ({...prev, trips: prev.trips.map(t => t.id === trip.id ? {...t, month: e.target.value} : t)}))} className="bg-slate-100 dark:bg-slate-900 rounded px-2 py-1 outline-none text-sm dark:text-white">
                        {MONTHS_BR.map(m => <option key={m} value={m}>{m}</option>)}
                      </select>
                    </div>
                    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-4">
                      {[
                        { label: 'Carro', field: 'carRental' },
                        { label: 'Combustível', field: 'fuel' },
                        { label: 'Alimentação', field: 'food' },
                        { label: 'Outros', field: 'others' },
                        { label: 'Cartão', field: 'creditCard' },
                        { label: 'Pix', field: 'pix' }
                      ].map(f => (
                        <div key={f.field}>
                          <label className="text-slate-400 text-[10px] uppercase font-bold">{f.label}</label>
                          <input type="number" step="any" value={(trip as any)[f.field] || ""} onChange={(e) => setData(prev => ({...prev, trips: prev.trips.map(t => t.id === trip.id ? {...t, [f.field]: parseFloat(e.target.value) || 0} : t)}))} className="w-full p-2 bg-slate-50 dark:bg-slate-900 rounded border dark:border-slate-700 dark:text-white outline-none" />
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </Card>
          )}
        </div>
      </main>

      <Modal isOpen={!!selectedMonthId} onClose={() => setSelectedMonthId(null)} title={`Editar: ${selectedMonth?.month || ''}`}>
        {selectedMonth && (
          <div className="space-y-8">
            <div className="flex items-center gap-6 p-4 bg-slate-50 dark:bg-slate-900/50 rounded-xl border dark:border-slate-700">
               <label className="text-sm font-bold dark:text-slate-300">Mês do Lançamento:</label>
               <select 
                 value={selectedMonth.month} 
                 onChange={(e) => {
                    const newMonthName = e.target.value;
                    setData(prev => ({
                      ...prev,
                      months: prev.months.map(m => m.id === selectedMonth.id ? { ...m, month: newMonthName } : m)
                    }));
                 }}
                 className="flex-1 bg-white dark:bg-slate-800 rounded-lg px-4 py-2 outline-none dark:text-white border focus:border-primary-500 font-bold"
