                   {formatCurrency(calculateTotalIncome(selectedMonth.income) - calculateTotalExpenses(selectedMonth.expenses))}
                </p>
              </div>
              <button 
                type="button"
                onClick={(e) => {
                  e.stopPropagation();
                  handleDeleteMonth(selectedMonth.id);
                }} 
                className="bg-red-500 hover:bg-red-600 text-white px-8 py-4 rounded-2xl flex items-center gap-2 transition-all font-black shadow-xl shadow-red-500/20 active:scale-95 group cursor-pointer border-none"
              >
