                   {formatCurrency(calculateTotalIncome(selectedMonth.income) - (calculateTotalExpenses(selectedMonth.expenses) + data.categorizedExpenses.filter(c => c.month === selectedMonth.month).reduce((a, b) => a + b.value, 0)))}
                </p>
